import React, { Component } from "react";
import Modal from "react-modal";
import { Table } from "react-bootstrap";
import ReactToPrint from "react-to-print";
import { ToWords } from "to-words";
import * as moment from "moment";
import "./bill-custom.css";
const toWords = new ToWords({
  localeCode: "en-IN",
  converterOptions: {
    currency: true,
    ignoreDecimal: false,
    ignoreZeroCurrency: false,
  },
});

const customStyles = {
  content: {
    top: "50%",
    left: "50%",
    right: "auto",
    bottom: "auto",
    // marginRight: '-50%',
    transform: "translate(-50%, -50%)",
    height: "600px", // <-- This sets the height
    overlfow: "scroll", // <-- This tells the modal to scrol
    minWidth: "70%",
  },
};

class PrintPriviewModal extends Component {
  constructor(props) {
    super(props);
    this.state = {
      openPopup: false,
      billItems: [],
      totalQty: 0,
      totalAmt: 0,
      pendingamtTotal: 0,
      pendingItems: 0,
      bill: "",
      billDate: "",
      branch: "",
      grouped: [],
      subTitle: "",
      phone: ''
    };
  }

  UNSAFE_componentWillReceiveProps(_nprops) {
    if (_nprops.open === true) {
      this.setState({
        openPopup: true,
        phone: _nprops.phone,

      });
      if (_nprops.subTitle) {
        this.setState({
          subTitle: _nprops.subTitle,
        });
      }
      if (_nprops.data) {
        if (_nprops.data.length > 0) {
          let qtyTotal = 0;
          let amtTotal = 0;
          let pedningamtTotal = 0;
          let pendingItems = 0;

          _nprops.data.forEach((item) => {
            qtyTotal = parseFloat(qtyTotal) + parseFloat(item.qty);
            amtTotal = parseFloat(amtTotal) + parseFloat(item.amt);
            if (item.status && item.status == 1) {
              pendingItems = parseFloat(pendingItems) + parseFloat(item.qty);
              pedningamtTotal =
                parseFloat(pedningamtTotal) + parseFloat(item.amt);
            }
          });
          this.setState({
            pendingItems: pendingItems,
            billItems: _nprops.data,
            totalQty: qtyTotal,
            totalAmt: amtTotal,
            pendingamtTotal: pedningamtTotal,
            branch: _nprops.data[0].branch,
            bill: _nprops.data[0].bill,
            billDate: _nprops.data[0].billDate,
            grouped: _nprops.groupedData,
          });
        }
      }
    }
  }

  closePopUp() {
    this.setState({
      openPopup: false,
      billItems: [],
      grouped: [],
    });
    this.props.closePopup();
  }

  getTotalItemsQty(pastries) {
    let totalItems = 0;
    pastries.forEach((oneItem) => {
      if (oneItem.qty) {
        totalItems = totalItems + parseFloat(oneItem.qty);
      }
    });
    return totalItems;
  }

  getTotalItemsQtyPending(pastries) {
    let totalItems = 0;
    pastries.forEach((oneItem) => {
      if (oneItem.status && oneItem.status == 1 && oneItem.qty) {
        totalItems = totalItems + parseFloat(oneItem.qty);
      }
    });
    return totalItems;
  }

  getTotalItemsQtyPrice(pastries) {
    let totalItemsPrice = 0;
    pastries.forEach((oneItem) => {
      if (oneItem.amt) {
        totalItemsPrice = totalItemsPrice + parseFloat(oneItem.amt);
      }
    });
    return totalItemsPrice;
  }

  getTotalItemsQtyPricePending(pastries) {
    let totalItemsPrice = 0;
    pastries.forEach((oneItem) => {
      if (oneItem.amt && oneItem.status && oneItem.status == 2) {
        totalItemsPrice = totalItemsPrice + parseFloat(oneItem.amt);
      }
    });
    return totalItemsPrice;
  }

  render() {
    return (
      <Modal
        isOpen={this.state.openPopup}
        ariaHideApp={false}
        // style={customStyles}
        contentLabel="Bill Modal"
      >
        <p
          className="close-modal close-modal-static"
          onClick={() => this.closePopUp()}
        >
          <i className="fa fa-times"></i>
        </p>

        <div ref={(el) => (this.componentRef = el)}>
          <Table
            bordered
            size="sm"
            className="margin-btm-0 zero-bottom-border table-head-item"
          >
            <tbody>
              <tr>
                <td colSpan="3" className="text-center pad-opx">
                  <h4>Black Forest Cakes</h4>
                  <p>
                    {this.state.branch ? this.state.branch + " branch" : ""},
                  </p>
                  {this.state.subTitle && <p>{this.state.subTitle}</p>}

                  <br />
                  {this.state.phone ? "PHONE: " + this.state.phone : ""}
                </td>
              </tr>
            </tbody>
          </Table>
          <Table
            bordered
            size="sm"
            className="bill-colmn margin-btm-0 zero-bottom-border table-head-item"
          >
            <tbody>
              <tr>
                <td className="pad-10px"> Bill No</td>
                <td className="pad-10px"> {this.state.bill}</td>
                <td> Bill Date</td>
                <td>
                  {" "}
                  {this.state.billDate
                    ? moment(this.state.billDate).format("DD/MM/YYYY")
                    : ""}
                </td>
              </tr>
            </tbody>
          </Table>
          <Table className="bill-item-table" size="sm">
            <thead>
              <tr>
                <th>S.No</th>
                <th>Particulars</th>
                <th>Category</th>
                <th>Rate</th>
                <th>Qty</th>
                <th>Amount</th>
              </tr>
            </thead>
            {Object.keys(this.state.grouped).map((key) => {
              return (
                <tbody key={key}>
                  <tr className="border-top-row">
                    <td colSpan="8" className="cat-title">
                      {key} - Total Items:{" "}
                      {this.getTotalItemsQty(this.state.grouped[key])} | Total
                      Pending Items:{" "}
                      {this.getTotalItemsQtyPending(this.state.grouped[key])} |
                      Total Cost:{" "}
                      {this.getTotalItemsQtyPrice(this.state.grouped[key])} |
                      Total Completed Cost:{" "}
                      {this.getTotalItemsQtyPricePending(
                        this.state.grouped[key]
                      )}
                    </td>
                  </tr>
                  {this.state.grouped[key].map((item, keyT) => {
                    return (
                      <tr key={keyT} className="border-top-row">
                        <td>{keyT + 1}</td>
                        <td>
                          {item.particulars}{" "}
                          {item.status && item.status == 1 && (
                            <span className="text-danger">(p)</span>
                          )}
                        </td>
                        <td>{item.categoryName}</td>
                        <td>₹ {item.rate}</td>
                        <td>{item.qty}</td>
                        <td>₹ {item.amt}</td>
                      </tr>
                    );
                  })}
                </tbody>
              );
            })}
            <tbody>
              {/* {this.state.billItems.length > 0 &&
                this.state.billItems.map((item, key) => {
                  return (
                    <tr key={key}>
                      <td>{key + 1}</td>
                      <td>{item.particulars}</td>
                      <td>₹ {item.rate}</td>
                      <td>{item.qty}</td>
                      <td>₹ {item.amt}</td>
                    </tr>
                  );
                })} */}
              {this.state.billItems.length > 0 && (
                <tr>
                  <td></td>
                  <td></td>
                  <td></td>
                  <td></td>
                  <td className="border-top">{this.state.totalQty}</td>
                  <td className="border-top">₹ {this.state.totalAmt}</td>
                </tr>
              )}
              {/* {this.state.billItems.length > 0 && (
                <tr className="border-top-row">
                  <td colSpan="3">Total Cost</td>
                  <td></td>
                  <td></td>
                  <td>₹ {this.state.totalAmt}</td>
                </tr>
              )}
              {this.state.billItems.length > 0 && (
                <tr className="border-top-row">
                  <td colSpan="7">
                    {toWords.convert(this.state.totalAmt, { currency: true })}
                  </td>
                </tr>
              )} */}
              {this.state.billItems.length > 0 && (
                <tr className="border-top-row">
                  <td>Total Cost</td>
                  <td colSpan="5">
                    ₹ {this.state.totalAmt}{" "}
                    {toWords.convert(this.state.totalAmt, {
                      currency: true,
                    })}
                  </td>
                </tr>
              )}
              {this.state.billItems.length > 0 && (
                <tr className="border-top-row">
                  <td>
                    {" "}
                    {this.state.pendingItems > 0
                      ? "Total Pending Cost of" +
                      this.state.pendingItems +
                      "items"
                      : "Total Pending Cost"}{" "}
                  </td>
                  <td colSpan="5">
                    ₹ {this.state.pendingamtTotal}{" "}
                    {toWords.convert(this.state.pendingamtTotal, {
                      currency: true,
                    })}
                  </td>
                </tr>
              )}

              <tr className="border-top-row">
                <td className="pad-10px" colSpan="7"></td>
              </tr>
              <tr>
                <td className="pad-10px" colSpan="7"></td>
              </tr>
              <tr>
                <td colSpan="7"></td>
              </tr>
            </tbody>
          </Table>
        </div>

        {this.state.billItems.length > 0 && (
          <ReactToPrint
            documentTitle={
              this.state.bill
                ? "Black-forest-bill-" + this.state.bill
                : "Black-forest-bill"
            }
            trigger={() => {
              return (
                <button id="printInvoice" className="btn btn-info">
                  <i className="fa fa-print"></i> Print
                </button>
              );
            }}
            content={() => this.componentRef}
          />
        )}
        <button
          className="btn btn-info mar-lft-10px"
          onClick={() => this.closePopUp()}
        >
          <i className="fa fa-times"></i> Close
        </button>
      </Modal>
    );
  }
}

export default PrintPriviewModal;
