import React, { Component } from "react";
import Modal from "react-modal";
import { Table } from "react-bootstrap";
import ReactToPrint from "react-to-print";
import { ToWords } from "to-words";

import "./bill-custom.css";
const _ = require("lodash");

const toWords = new ToWords({
  localeCode: "en-IN",
  converterOptions: {
    currency: true,
    ignoreDecimal: false,
    ignoreZeroCurrency: false,
  },
});

const customStyles = {
  content: {
    top: "50%",
    left: "50%",
    right: "auto",
    bottom: "auto",
    // marginRight: '-50%',
    transform: "translate(-50%, -50%)",
    height: "600px", // <-- This sets the height
    overlfow: "scroll", // <-- This tells the modal to scrol
    minWidth: "70%",
  },
};

class ReportOrdersModal extends Component {
  constructor(props) {
    super(props);
    this.state = {
      openPopup: false,
      billItems: [],
      branch: "",
      loader: false,
      totalOrders: 0,
      totalAmt: 0,
      grouped: [],
      returns: [],
      branchOrderVal: 0,
      regularOrdersTotal: 0,
      stockOrderVal: 0,
      orderto: '',
      orderfrom: '',
      deliveryToDate: '',
      deliveryFromDate: '',
      branchMobile: ''
    };
  }

  UNSAFE_componentWillReceiveProps(_nprops) {
    if (_nprops.open === true) {
      this.setState({
        openPopup: true,
        loader: _nprops.loader,
      });
      if (_nprops.data) {
        if (_nprops.data.length > 0) {
          this.setState({
            orderto: _nprops.orderto,
            orderfrom: _nprops.orderfrom,
            deliveryToDate: _nprops.deliveryToDate,
            deliveryFromDate: _nprops.deliveryFromDate,
            billItems: _nprops.data,
            totalOrders: _nprops.totalOrder,
            totalAmt: _nprops.totalSales,
            branch: _nprops.branch,
            grouped: _nprops.groupedData,
            returns: _nprops.returnOrders,
            branchOrderVal: _nprops.branchOrderVal,
            regularOrdersTotal: _nprops.regularOrdersTotal,
            stockOrderVal: _nprops.stockOrderVal,
            branchMobile: _nprops.branchMobile
          });
        }
      }
    }
  }

  closePopUp() {
    this.setState({
      openPopup: false,
      billItems: [],
      grouped: [],
      returns: [],
      branch: "",
    });
    this.props.closePopup();
  }

  getTotalAmountOfReturn(items) {
    let tAmont = 0;
    items.forEach((element) => {
      tAmont = parseFloat(tAmont) + parseFloat(element.price);
    });
    return tAmont;
  }

  getTotalOrdersOfReturn(items) {
    let _tOrders = 0;
    items.forEach((element) => {
      _tOrders = parseFloat(_tOrders) + parseFloat(element.qty);
    });
    return _tOrders;
  }

  getRowData(pastries) {
    const grouped = _.groupBy(pastries, function (order) {
      return order.name;
    });

    const productData = [];
    let rateproduct = 0;
    Object.keys(grouped).map((key) => {
      let productTotalQty = 0;
      let totalPrice = 0;
      rateproduct = grouped[key][0] ? grouped[key][0].rate : "0";
      grouped[key].forEach((item) => {
        if (item.qty) {
          productTotalQty = parseFloat(productTotalQty) + parseFloat(item.qty);
        }

        if (item.amount) {
          totalPrice = totalPrice + parseFloat(item.amount);
        }
      });
      productData.push({
        id: key,
        name: key,
        price: rateproduct,
        totalAmt: productTotalQty,
        totalPrice: totalPrice,
        unParsed: grouped[key],
      });
    });
    return productData;
  }
  getBranchLists(data) {
    const groupedByEmp = _.groupBy(data, function (order) {
      return order.employee ? order.employee._id : null;
    });

    // let branchData = "";

    let branchData = [];
    Object.keys(groupedByEmp).map((key) => {
      if (groupedByEmp[key] && groupedByEmp[key][0]) {
        let branchQty = 0;
        let branchName = groupedByEmp[key][0].employee
          ? groupedByEmp[key][0].employee.firstname
            ? groupedByEmp[key][0].employee.firstname +
            " " +
            groupedByEmp[key][0].employee.lastname
            : groupedByEmp[key][0].employee.branch
          : "N/A";
        groupedByEmp[key].forEach((item) => {
          if (item.qty) {
            branchQty = branchQty + parseFloat(item.qty);
          }
        });
        branchData.push({ name: branchName.slice(0, 3), qty: branchQty });
        // branchData += branchName.slice(0, 3) + "(" + branchQty + ") ";
      }
    });
    // return (<table> {
    //   branchData.map((mapItem, k) => {
    //     return <tr key={('Map-Item-Key' + k).toString()}><td>{mapItem}</td></tr>
    //   })
    // } </table>);
    return (
      <table className="mini-table">
        <thead>
          <tr className="tr-btm">
            {
              branchData.map((mapItem, k) => {
                return <td className="th-ri" key={('Map-Item-head-Key' + k).toString()}>{mapItem.name}</td>
              })
            }
          </tr>
        </thead>
        <tbody>
          <tr>
            {
              branchData.map((mapItem, k) => {
                return <td className="th-ri" key={('Map-Item-Key' + k).toString()}>{mapItem.qty}</td>
              })
            }
          </tr>
        </tbody>
      </table>
    );
  }

  getTotalCategoryItems(pastries) {
    let qty = 0;
    pastries.forEach((item) => {
      if (item.qty) {
        qty = qty + parseFloat(item.qty);
      }
    });
    return qty;
  }

  getTotalCategoryItemsPendings(pastries) {
    let qty = 0;
    pastries.forEach((item) => {
      if (item.qty && item.status == 1) {
        qty = qty + parseFloat(item.qty);
      }
    });
    return qty;
  }

  getTotalCategoryItemsCost(pastries) {
    let qty = 0;
    pastries.forEach((item) => {
      if (item.amount) {
        qty = qty + parseFloat(item.amount);
      }
    });
    return qty;
  }

  getTotalCategoryItemsCostPending(pastries) {
    let qty = 0;
    pastries.forEach((item) => {
      if (item.amount && item.status == 1) {
        qty = qty + parseFloat(item.amount);
      }
    });
    return qty;
  }

  getAllTotalItems(pastries) {
    let totalQty = 0;
    pastries.forEach((oneItem) => {
      if (oneItem.qty) {
        totalQty = totalQty + parseFloat(oneItem.qty);
      }
    });
    return totalQty.toFixed(2);
  }

  render() {
    return (
      <Modal
        isOpen={this.state.openPopup}
        ariaHideApp={false}
        // style={customStyles}
        contentLabel="Bill Modal"
      >
        <p
          className="close-modal close-modal-static"
          onClick={() => this.closePopUp()}
        >
          <i className="fa fa-times"></i>
        </p>

        <div ref={(el) => (this.componentRef = el)}>
          <Table
            bordered
            size="sm"
            className="margin-btm-0 zero-bottom-border table-head-item"
          >
            <tbody>
              <tr>
                <td colSpan="3" className="text-center pad-opx">
                  <h4>Black Forest Cakes</h4>
                  {this.state.branch && <p>{this.state.branch}</p>}
                  {this.state.branchMobile && <p>{this.state.branchMobile}</p>}
                </td>
              </tr>
              <tr>
                <td colSpan="3" className="text-center pad-op font12x">
                  {this.state.orderfrom ? ('Order From Date: ' + this.state.orderfrom) : ''} {this.state.orderto ? (' | Order To Date: ' + this.state.orderto) : ''} {this.state.deliveryFromDate ? (' | Delivery From Date: ' + this.state.deliveryFromDate) : ''} {this.state.deliveryToDate ? (' | Delivery To Date: ' + this.state.deliveryToDate) : ''}
                </td>
              </tr>
            </tbody>
          </Table>
          <Table className="bill-item-table" size="sm">
            <thead>
              <tr>
                <th>S.No</th>
                <th>Particulars</th>
                <th>Rate</th>
                <th>Qty</th>
                <th>Total</th>
                <th>Details</th>
              </tr>
            </thead>
            <tbody>
              {this.state.loader === true && (
                <tr className="border-top-row">
                  <td className="pad-10px" colSpan="6">
                    Loading huge items please wait...
                  </td>
                </tr>
              )}
              {/* {this.state.billItems.length > 0 &&
                this.state.billItems.map((item, key) => {
                  return (
                    <tr key={key}>
                      <td>{key + 1}</td>
                      <td>{item.name}</td>
                      <td>{item.type}</td>
                      <td>{item.qty}</td>
                      <td>₹ {item.amount}</td>
                      <td>₹ {item.date}</td>
                    </tr>
                  );
                })} */}
              {Object.keys(this.state.grouped).map((key) => {
                return (
                  <>
                    <tr className="border-top-row" key={'map-' + key}>
                      <td td colSpan="6" className="cat-title">
                        {key} - Total Items :{" "}
                        {this.getTotalCategoryItems(this.state.grouped[key])} |
                        Total Pending Items:
                        {this.getTotalCategoryItemsPendings(
                          this.state.grouped[key]
                        )}{" "}
                        | Total Amount: ₹{" "}
                        {this.getTotalCategoryItemsCost(
                          this.state.grouped[key]
                        )}{" "}
                        | Total Amount Of Pendings: ₹{" "}
                        {this.getTotalCategoryItemsCostPending(
                          this.state.grouped[key]
                        )}
                      </td>
                    </tr>
                    {this.getRowData(this.state.grouped[key]).length > 0 &&
                      this.getRowData(this.state.grouped[key]).map(
                        (_item, key) => {
                          return (
                            <tr className="border-bottom" key={_item.id}>
                              <td>{key + 1}</td>
                              <td>{_item.name}</td>
                              <td>₹ {_item.price}</td>
                              <td>{_item.totalAmt}</td>
                              <td>₹ {_item.totalPrice}</td>
                              <td>{this.getBranchLists(_item.unParsed)}</td>
                            </tr>
                          );
                        }
                      )}
                    {/* {this.state.grouped[key].map((item, keyT) => {
                      return (
                        <tr key={keyT} className="border-top-row">
                          <td>{keyT + 1}</td>

                          <td>{item.name}</td>
                          <td>{item.categoryName}</td>
                          <td>{item.type}</td>
                          <td>{item.qty}</td>
                          <td>₹ {item.amount}</td>
                          <td>₹ {item.date}</td>
                        </tr>
                      );
                    })} */}
                  </>
                );
              })}
              {this.state.billItems.length > 0 && (
                <tr className="border-top-row">
                  <td className="pad-10px" colSpan="2">
                    Regular Orders ₹ {this.state.regularOrdersTotal}
                  </td>
                  <td className="pad-10px" colSpan="2">
                    Branch Orders ₹ {this.state.branchOrderVal}
                  </td>{" "}
                  <td className="pad-10px" colSpan="2">
                    Stock Orders ₹ {this.state.stockOrderVal}
                  </td>
                </tr>
              )}
              {this.state.billItems.length > 0 && (
                <tr className="border-top-row">
                  <td className="pad-10px" colSpan="3">
                    Total
                  </td>
                  <td>{this.getAllTotalItems(this.state.billItems)}</td>
                  <td className="pad-10px">
                    {" "}
                    ₹ {this.state.totalAmt.toFixed(2)}
                  </td>
                  <td></td>
                </tr>
              )}
              {/* {this.state.returns.length > 0 && (
                <tr className="border-top-row">
                  <td className="pad-10px" colSpan="3">
                    Total Return Orders
                  </td>
                  <td className="pad-10px">
                    {this.getTotalOrdersOfReturn(this.state.returns)}
                  </td>
                  <td className="pad-10px">
                    {" "}
                    ₹{this.getTotalAmountOfReturn(this.state.returns)}
                  </td>
                  <td></td>
                </tr>
              )} */}
              {/* {this.state.returns.length > 0 && (
                <tr className="border-top-row">
                  <td className="pad-10px" colSpan="4">
                    Net Total
                  </td>
                  <td className="pad-10px">
                    {" "}
                    ₹{" "}
                    {this.state.totalAmt.toFixed(2) -
                      this.getTotalAmountOfReturn(this.state.returns)}
                  </td>
                  <td></td>
                </tr>
              )} */}

              <tr>
                <td colSpan="8"></td>
              </tr>
            </tbody>
          </Table>
        </div>

        {this.state.billItems.length > 0 && (
          <ReactToPrint
            documentTitle={"Black-forest-order-report"}
            trigger={() => {
              return (
                <button id="printInvoice" className="btn btn-info">
                  <i className="fa fa-print"></i> Print
                </button>
              );
            }}
            content={() => this.componentRef}
          />
        )}

        <button
          className="btn btn-info mar-lft-10px"
          onClick={() => this.closePopUp()}
        >
          <i className="fa fa-times"></i> Close
        </button>
      </Modal>
    );
  }
}

export default ReportOrdersModal;
