    openPrintPopUpModal() {
        this.setState({
            openPrintPopUp: true
        });
    }

    closePopup() {
        this.setState({
            openPrintPopUp: false,
            branchName: ''
        });
    }

    categorySelection(selectedList) {
        const tempSelected = [];
        selectedList.forEach(item => {
            tempSelected.push(item._id)
        })
        this.setState({
            selectedCategories: tempSelected
        })
        this.getAllProductsByCategory(tempSelected);
    }

    getAllProductsByCategory(category) {
        this.setState({
            productsByCategory: [],
            pastryProductsByCategory: []
        });
        if (category && category.length > 0) {
            axios({
                method: "GET",
                url: apiUrls.PRODUCT.getAllGeneralProducts,
                headers: {
                    Authorization: authHeader(),
                },
                params: { categories: category },
            })
                .then((result) => {
                    if (result.status === 200) {
                        this.setState({
                            productsByCategory: result.data.data,
                        });
                    } else {
                        this.setState({
                            productsByCategory: [],
                        });
                    }
                })
                .catch((e) => {
                    this.setState({
                        productsByCategory: [],
                    });
                });

            axios({
                method: "GET",
                url: apiUrls.PRODUCT.getAllProductByCategory,
                headers: {
                    Authorization: authHeader(),
                },
                params: { categories: category },
            })
                .then((result) => {
                    if (result.status === 200) {
                        this.setState({
                            pastryProductsByCategory: result.data.data,
                        });
                    } else {
                        this.setState({
                            pastryProductsByCategory: [],
                        });
                    }
                })
                .catch((e) => {
                    this.setState({
                        pastryProductsByCategory: [],
                    });
                });
        }
    }

    productSelection(selectedList) {
        const tempSelected = [];
        selectedList.forEach((item) => {
            tempSelected.push(item._id);
        });
        this.setState(
            {
                selectedProducts: tempSelected,
            });
    }

    getTotalAmountOfReturn(items) {
        let tAmont = 0;
        items.forEach((element) => {
            tAmont = parseFloat(tAmont) + parseFloat(element.price);
        });
        return (tAmont).toFixed(2);
    }


