                    categoryName: this.getProductCategoryName(pastry.data, this.state.liveOrders[0].pastryDetails),
                    rate: pastry.data.price,
                    qty: pastry.data.sendQty,
                    amt: pastry.data.price * pastry.data.sendQty,
