    getData(_status, _categories, _products) {
        if (this.state.oneBillid) {
            this.setState({
                oneBillOrder: [],
                liveLoader: true
            });
            var params = {};

            if (_status) {
                params.currBillStatus = _status
            } else if (this.state.currBillStatus) {
                params.currBillStatus = this.state.currBillStatus
            }

            if (_categories) {
                params.category = _categories;
            } else if (this.state.selectedCategories2.length > 0) {
                params.category = this.state.selectedCategories2;
            }

            if (_products) {
                params.filterProducts = _products;
            } else if (this.state.selectedProducts2) {
                params.filterProducts = this.state.selectedProducts2;
            }

            if (this.state.orderfrom) {
                params.createdDate = moment(this.state.orderfrom).format('YYYY-MM-DD')
            }

            if (this.state.orderto) {
                params.createdDateEnd = moment(this.state.orderto).format('YYYY-MM-DD')
            }

            axios({
                method: "GET",
                url: apiUrls.ORDERS.billOrder + "/" + this.state.oneBillid,
                headers: {
                    Authorization: authHeader(),
                },
                params: params,
            })
                .then((result) => {
                    if (result.status === 200 && result.data.data) {
                        result.data.data[0].pastry.sort(function (o1, o2) {
                            return new Date(o1.delivery_date) - new Date(o2.delivery_date);
                        });
                        let respData = result.data.data;
                        let _tempOrder = respData[0].pastries
                        _tempOrder = _.orderBy(_tempOrder, ['data.delivery_date'], ['asc']); // Use Lodash to sort array by 'name'
                        respData[0].pastries = _tempOrder

                        this.setState({
                            liveLoader: false,
                            oneBillOrder: respData,
                            completedOrderPayment: result.data.payment
                                ? result.data.payment
                                : null,
                        });
                    } else {
                        this.setState({
                            oneBillOrder: [],
                            liveLoader: false
                        });
                    }
                })
                .catch((e) => {
                    this.setState({
                        oneBillOrder: [],
                        liveLoader: false
                    });
                });
        }
    }

