    getProductName(selected, items) {
        let name = "-";
        items.forEach((element) => {
            if (element.info._id === selected._id) {
                name = element.info.name;
            }
        });
        return name;
    }

    getProductCategoryName(selected, items) {
        let name = 'NA';
        items.forEach(element => {
            if (element.info._id === selected._id) {
                name = (element.info.categoryData && element.info.categoryData[0]) ? element.info.categoryData[0].name : 'NA'
            }
        });
        return name;
    }

    getUnitName(selected, items) {
        let unit = "";
        items.forEach((element) => {
            if (element.info._id === selected._id) {
                unit = element.info.unitDetails ? element.info.unitDetails.name : "";
            }
        });
        return unit;
    }

    getTotalAmount2(items) {
        let totalPrice = 0;
        items.forEach(element => {
            const onePrice = element.price * element.sendQty;
            totalPrice = totalPrice + parseFloat(onePrice)
        });
        return totalPrice;
    }

    getTotalAmount(items) {
        let totalPrice = 0;
        items.forEach((element) => {
            if (element.data) {
                const onePrice = element.data.price * element.data.sendQty;
                totalPrice = totalPrice + parseFloat(onePrice);
            }
        });
        return totalPrice;
    }

    getTotalAmountOrdered(items) {
        let totalPrice = 0;
        items.forEach((element) => {
            const onePrice = element.price * element.qty;
            totalPrice = totalPrice + parseFloat(onePrice);
        });
        return totalPrice;
    }

    getTotalorders(items) {
        let total = 0;
        items.forEach((element) => {
            total = total + 1;
        });
        return total;
    }
    getTotalSendItemorders(items) {
        let total = 0;
        items.forEach((element) => {
            if (element.data && element.data.sendQty) {
                total = total + parseFloat(element.data.sendQty);
            }
        });
        return total;
    }

    getTotalOrderedItemorders(items) {
        let total = 0;
        items.forEach((element) => {
            if (element.qty) {
                total = total + parseFloat(element.qty);
            }
        });
        return total;
    }

    getTotalPendingorders(items) {
        let total = 0;
        items.forEach((element) => {
            if (element.status == "1") total = total + 1;
        });
        return total;
    }
    getTotalCompletedorders(items) {
        let total = 0;
        items.forEach((element) => {
            if (element.status == "2") total = total + 1;
        });
        return total;
    }

