    deleteOneOrderItem(orderId, pastry) {
        if (window.confirm("Are sure to delete this item!")) {
            var _notificationSystem = this.refs.notificationSystem;
            axios({
                method: "POST",
                url: apiUrls.ORDERS.removeOneBranchItem,
                data: {
                    order: orderId,
                    pastryId: pastry
                },
                headers: {
                    "Content-Type": "application/json",
                    Authorization: authHeader(),
                },
            })
                .then((result) => {
                    if (result.status === 200) {

                        if (result.data && result.data.refresh === true) {
                            this.getFilterRecords();
                            this.setState({
                                oneBillOrderShow: false
                            })
                        } else {
                            this.getData();
                            this.getFilterRecords();
                        }
                        _notificationSystem.addNotification({
                            title: <span data-notify="icon" className="pe-7s-check" />,
                            message: <div>Removed.</div>,
                            level: "success",
                            position: "tr",
                            autoDismiss: 15,
                        });
                    }
                })
                .catch((e) => {
                    console.log(e);
                    _notificationSystem.addNotification({
                        title: <span data-notify="icon" className="pe-7s-close-circle" />,
                        message: (
                            <div>
                                {e.response ? e.response.data.message : "Something went wrong!"}
                            </div>
                        ),
                        level: "error",
                        position: "tr",
                        autoDismiss: 15,
                    });
                });
        }

    }

    getTotal(type) {
        let total = 0;

        if (type === 'items') {
            this.state.searchRecords.forEach(i => {
                i.pastry.forEach(p => {
                    total = total + 1;
                })
            })
        }

        if (type === 'bill_val') {
            this.state.searchRecords.forEach(i => {
                i.pastry.forEach(element => {
                    const onePrice = element.price * element.qty;
                    total = total + parseFloat(onePrice);
                })
            })
        }

        if (type === 'completed_items') {
            this.state.searchRecords.forEach(i => {
                i.pastry.forEach(element => {
                    if (element.status == "2") {
                        total = total + 1;
                    }
                })
            })
        }
        if (type === 'pending_items') {
            this.state.searchRecords.forEach(i => {
                i.pastry.forEach(element => {
                    if (element.status == "1") {
                        total = total + 1;
                    }
                })
            })
        }
        if (type === 'send_bill_val') {
            this.state.searchRecords.forEach(i => {
                i.pastry.forEach(element => {
                    const onePrice = element.price * element.sendQty;
                    total = total + parseFloat(onePrice)

                })
            })
        }

        return total;
    }

