
import React, { Component } from "react";
import { NavLink } from "react-router-dom";

import AdminNavbarLinks from "../Navbars/AdminNavbarLinks.jsx";

import logo from "assets/img/Black-Forest-Logo.png";

class Sidebar extends Component {
  constructor(props) {
    super(props);
    this.state = {
      width: window.innerWidth
    };
  }

  updateDimensions() {
    this.setState({ width: window.innerWidth });
  }
  componentDidMount() {
    this.updateDimensions();
    window.addEventListener("resize", this.updateDimensions.bind(this));
  }

  render() {
    const sidebarBackground = {
      backgroundImage: "url(" + this.props.image + ")"
    };
    const fullWidth = {
      width: '100%'
    };
    return (
      <div
        id="sidebar"
        className="sidebar sidebar-brown"
        data-color={this.props.color}
        data-image={this.props.image}
      >
        {/* {this.props.hasImage ? (
          <div className="sidebar-background" style={sidebarBackground} />
        ) : (
            null
          )} */}
        <div className="logo">
          {/* <a
            href=""
            className="simple-text logo-normal"
          > */}
          <img src={logo} style={fullWidth} alt="logo_image" />
          {/* </a> */}
        </div>
        <div className="sidebar-wrapper">
          <ul className="nav">
            {this.state.width <= 991 ? <AdminNavbarLinks /> : null}
            <li className={this.props.location.pathname === '/admin/user' ? 'active' : null}>
              <NavLink to="/admin/user" className="nav-link" activeClassName="active">
                <i className="pe-7s-user" /> <p>Profile</p>
              </NavLink>
            </li>
            <li className={this.props.location.pathname === '/admin/live-branches-order' ? 'active' : null}>
              <NavLink to="/admin/live-branches-order" className="nav-link" activeClassName="active">
                <i className="fa fa-shopping-cart" /> <p>Live Branch Orders</p>
              </NavLink>
            </li>
            
            <li className={this.props.location.pathname === '/admin/branches-order' ? 'active' : null}>
              <NavLink to="/admin/branches-order" className="nav-link" activeClassName="active">
                <i className="pe-7s-wallet" /> <p>Branch Orders</p>
              </NavLink>
            </li>
            <li className={this.props.location.pathname === '/admin/stock-orders' ? 'active' : null}>
              <NavLink to="/admin/stock-orders" className="nav-link" activeClassName="active">
                <i className="fa fa-archive" /> <p>Stock Orders</p>
              </NavLink>
            </li>
            <li className={this.props.location.pathname === '/admin/return-orders' ? 'active' : null}>
              <NavLink to="/admin/return-orders" className="nav-link" activeClassName="active">
                <i className="fa fa-undo" /> <p>Return Orders</p>
              </NavLink>
            </li>
            <li className={this.props.location.pathname === '/admin/payments' ? 'active' : null}>
              <NavLink to="/admin/payments" className="nav-link" activeClassName="active">
                <i className="fa fa-money" /> <p>Payments</p>
              </NavLink>
            </li>
            <li className={this.props.location.pathname === '/admin/user-tracking' ? 'active' : null}>
              <NavLink to="/admin/user-tracking" className="nav-link" activeClassName="active">
                <i className="pe-7s-map-2" /> <p>User Track</p>
              </NavLink>
            </li>
            {/* <li className={this.props.location.pathname === '/admin/report-product' ? 'active' : null}>
              <NavLink to="/admin/report-product" className="nav-link" activeClassName="active">
                <i className="pe-7s-copy-file" /> <p>Reports by product</p>
              </NavLink>
            </li> */}
            <li className={this.props.location.pathname === '/admin/report-order' ? 'active' : null}>
              <NavLink to="/admin/report-order" className="nav-link" activeClassName="active">
                <i className="pe-7s-copy-file" /> <p>Reports by order</p>
              </NavLink>
            </li>
          </ul>
        </div>
      </div>
    );
  }
}

export default Sidebar;
