
import React, { Component } from "react";
import { Grid, Row, Col, Table } from "react-bootstrap";
import { Link } from "react-router-dom";
import axios from 'axios';
import NotificationSystem from "react-notification-system";
import Button from "components/CustomButton/CustomButton.jsx";
import * as moment from 'moment';

import { style } from "../../variables/Variables.jsx";
import Card from "components/Card/Card.jsx";
import '../../assets/css/custom.css';
import { authHeader } from '../../configs/helpers';
import { ApiUrlHost,  apiUrls } from '../../configs/configs';

const mgr2 = {
  marginRight: 2
};

class PastryOrdersList extends Component {
  constructor(props) {
    super(props);
    this.state = {
      collections: [],
      currentPage: 0,
      loading: true,
      totalRec: 0,
      branch: null,
      status: null,
      employees: [],
      sort: null,
      employee: null,
      category: null,
      categoryCol: []
    };
    this.paginationCall = this.paginationCall.bind(this);
    this.prevRecords = this.prevRecords.bind(this);
    this.nextRecords = this.nextRecords.bind(this);
    this.searchCall = this.searchCall.bind(this);
  }

  componentWillMount() {
    this.getAllUnits(null);
    this.getCategoryList();
    this.getAllBranchEmployees();
  }


  getCategoryList(){
    axios({
      method: 'GET',
      url: apiUrls.PRODUCT.getAllCategoryPastry,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200) {
        this.setState({
          categoryCol: result.data.data,
        });
      }else{
        this.setState({
          categoryCol : []
        });
      }
    }).catch(e => {
      this.setState({
        categoryCol : []
      });
    });
  }


  getAllBranchEmployees() {

    axios({
      method: 'GET',
      url: apiUrls.BRANCH_EMPLOYEE_LIST,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200 && result.data.data) {
        console.log(result.data.data)
        this.setState({
          employees: result.data.data,
        });
      } else {
        this.setState({
          employees: [],
        });
      }
    }).catch(e => {
      this.setState({
        employees: []
      });

    });
  }

  getAllUnits(search) {
    var _notificationSystem;

    var params = {
      page: this.state.currentPage
    };

    if (this.state.branch) {
      params.branch = this.state.branch
    }

    if (this.state.category) {
      params.category = this.state.category
    }

    if (this.state.status) {
      params.status = this.state.status
    }
    if (this.state.sort) {
      params.sortBy = this.state.sort;
    }

    if (this.state.employee) {
      params.user = this.state.employee;
    }
    this.setState({ _notificationSystem: this.refs.notificationSystem }, () => {
      _notificationSystem = this.refs.notificationSystem;
    });

    axios({
      method: 'GET',
      url: apiUrls.ORDERS.pastrylist,
      headers: {
        Authorization: authHeader()
      },
      params: params
    }).then(result => {

      if (result.status === 200 && result.data.data[0]) {
        this.setState({
          collections: result.data.data[0].paginatedResults,
          totalRec: result.data.data[0].totalCount[0] ? result.data.data[0].totalCount[0].count : 0,
          loading: false
        });
      } else {
        this.setState({
          collections: [],
          loading: false
        });
      }
    }).catch(e => {
      this.setState({
        collections: [],
        loading: false
      });

      _notificationSystem.addNotification({
        title: <span data-notify="icon" className="pe-7s-close-circle" />,
        message: (
          <div>
            {(e.response) ? e.response.data.message : 'Something went wrong!'}
          </div>
        ),
        level: 'error',
        position: "tr",
        autoDismiss: 15
      });
    });
  }

  paginationCall(index) {
    this.setState({
      currentPage: index
    }, () => {
      this.getAllUnits(null);
    })
  }

  prevRecords() {
    if (this.state.currentPage > 0) {
      var c = this.state.currentPage;
      this.setState({
        currentPage: c - 1
      }, () => {
        this.getAllUnits(null);
      })
    }
  }

  nextRecords() {
    var c = this.state.currentPage;
    var totalPage = Math.ceil(this.state.totalRec / 5);
    if (c < totalPage - 1) {
      this.setState({
        currentPage: c + 1
      }, () => {
        this.getAllUnits(null);
      })
    }
  }

  searchCall(val) {
    this.getAllUnits(val);
  }


  searchCallBranch = (branch) => {
    this.setState({ branch: branch }, () => { this.getAllUnits(null) })
  }

  searchCallByCategory = (category) => {
    this.setState({ category: category }, () => { this.getAllUnits(null) })
  }

  searchByDate = (date) => {
    this.setState({ sort: date }, () => { this.getAllUnits(null) })
  }

  searchByBranchEmp = (id) => {
    this.setState({ employee: id }, () => { this.getAllUnits(null) })
  }

  searchCallStatus = (status) => {
    this.setState({ status: status }, () => { this.getAllUnits(null) })
  }

  downloadReport = () => {
    var _notificationSystem;

    this.setState({ _notificationSystem: this.refs.notificationSystem }, () => {
      _notificationSystem = this.refs.notificationSystem;
    });

    var params = {
    };

    if (this.state.branch) {
      params.branch = this.state.branch
    }

    if (this.state.category) {
      params.category = this.state.category
    }

    if (this.state.status) {
      params.status = this.state.status
    }
    if (this.state.sort) {
      params.sortBy = this.state.sort;
    }

    if (this.state.employee) {
      params.user = this.state.employee;
    }

    axios({
      method: 'GET',
      url: apiUrls.ORDERS.downloadPastry,
      headers: {
        Authorization: authHeader()
      },
      params: params
    }).then(result => {
      if (result.data.filename) {
        window.open(ApiUrlHost + '/' + result.data.filename);
      }
    }).catch(e => {
      console.log(e, apiUrls.ORDERS.download)
      _notificationSystem.addNotification({
        title: <span data-notify="icon" className="pe-7s-close-circle" />,
        message: (
          <div>
            {(e.response) ? e.response.data.message : 'Something went wrong!'}
          </div>
        ),
        level: 'error',
        position: "tr",
        autoDismiss: 15
      });
    });
  }

  deleteOrder(orderId) {
    var _notificationSystem;
    this.setState({ _notificationSystem: this.refs.notificationSystem }, () => {
      _notificationSystem = this.refs.notificationSystem;
    });

    axios({
      method: 'DELETE',
      url: apiUrls.ORDERS.getOnePastry + orderId,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200) {
        if (this.state.currentPage != 0 && this.state.employees.length == 1) {
          this.setState({
            currentPage: this.state.currentPage - 1
          })
        }
        this.getAllUnits(null);

        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-check" />,
          message: (
            <div>
              Order deleted!.
            </div>
          ),
          level: 'success',
          position: "tr",
          autoDismiss: 15
        });
      }
    }).catch(e => {
      _notificationSystem.addNotification({
        title: <span data-notify="icon" className="pe-7s-close-circle" />,
        message: (
          <div>
            {(e.response) ? e.response.data.message : 'Something went wrong!'}
          </div>
        ),
        level: 'error',
        position: "tr",
        autoDismiss: 15
      });
    });
  }


  render() {
    return (
      <div className="content">
        <NotificationSystem ref="notificationSystem" style={style} />
        <Grid fluid>
          <Row>
            <Col md={12}>

              <Card
                title="Orders"
                categoryCol={this.state.categoryCol}
                branchHeadSearch={true}
                // search={true}
                empList={this.state.employees}
                orderSearch={true}
                noStatusSearch={true}
                searchplaceholder="Search by name"
                ctTableFullWidth
                ctTableResponsive
                pagination={this.state.collections.length > 0 ? true : false}
                processPagination={this.paginationCall}
                prev={this.prevRecords}
                next={this.nextRecords}
                searchCallBranch={(b) => this.searchCallBranch(b)}
                searchCallByCategory={(s) => this.searchCallByCategory(s)}
                searchByDate={(s) => this.searchByDate(s)}
                searchByBranchEmp={(s) => this.searchByBranchEmp(s)}
                currentPage={this.state.currentPage}
                totalPages={Math.ceil(this.state.totalRec / 5)}
                createLink="/admin/product-unit/create"
                branchesList={this.state.branches}
                downloadReport={this.downloadReport}
                content={

                  <Table striped hover>
                    <thead>
                      <tr>
                        <th>Id</th>
                        <th>OrderNo</th>
                        <th>Qty</th>
                        <th>Price</th>
                        <th>Ordered By</th>
                        <th>Ordered Date</th>
                        <th>Actions</th>
                      </tr>
                    </thead>
                    <tbody>
                      {(this.state.loading == false && this.state.collections.length > 0) && (
                        this.state.collections.map((element, index) => {
                          return (
                            <tr key={index}>
                              <td>{index + 1}</td>
                              <td>{element.form_no}</td>
                              <td>{element.qty}</td>
                              <td>{element.total}</td>
                              <td>{element.employeeDetail ? element.employeeDetail.firstname : '-'}</td>
                              <td>{moment(element.created_at).format('DD-MM-YYYY')} @ {moment(element.created_at).format('h:mm a')}</td>

                              <td>

                                <Link className="mgr-5 btn btn-default" to={"/admin/pastry-order/" + element._id} type="button" >
                                  View
                                </Link>
                               
                                <Button bsStyle="danger" onClick={() => this.deleteOrder(element._id)} type="button" style={mgr2}>
                                  Delete
                                </Button>
                              </td>
                            </tr>
                          );
                        })

                      )}

                      {(this.state.loading == false && this.state.collections.length == 0) && (
                        <tr>
                          <td colSpan={7} className="text-center">No Records Found</td>
                        </tr>
                      )}

                    </tbody>

                  </Table>
                }

              />
            </Col>

          </Row>
        </Grid>
      </div>
    );
  }
}

export default PastryOrdersList;
