
import React, { Component } from "react";
import { Grid } from "react-bootstrap";
import L from 'leaflet';
import axios from 'axios';
import 'leaflet/dist/leaflet.css';
import Marker from '../../assets/img/pin.png';
import EndMarker from '../../assets/img/birthday.png';
import ProfileDef from '../../assets/img/default-avatar.png';
import { authHeader, getTypeName } from '../../configs/helpers';
import { ApiUrlHost, apiUrls, SOCKETURL } from '../../configs/configs';
import socketIOClient from "socket.io-client";

const socket = socketIOClient(SOCKETURL);

class TrackingUser extends Component {
    map;
    constructor(props){
        super(props);
        this.state = {
            mapMarkers: [],
            deliveryManMessage: '',
            deliveryLocationMessage: '',
            movementMarker: '',
            destMarker: ''
        }
    }

    componentDidMount() {
        this.map = L.map('map', {
            center: [8.7642, 78.1348],
            zoom: 12
        });
        socket.on("location_change", ()=>{
            this.getTractRecords()
        });
        this.getTractRecords()
    }

    getTractRecords() {
        if(this.state.movementMarker){
            this.map.removeLayer(this.state.movementMarker);
        }

        const startIcon = L.icon({
            iconUrl: Marker, //'https://toppng.com/public/uploads/preview/eat-play-do-icon-map-marker-115548254600u9yjx6qhj.png',
            iconSize: [38, 38], // size of the icon
            iconAnchor: [22, 94], // point of the icon which will correspond to marker's location
            popupAnchor: [-3, -76] // point from which the popup should open relative to the iconAnchor
        });

        const endIcon = L.icon({
            iconUrl: EndMarker, //'https://toppng.com/public/uploads/preview/eat-play-do-icon-map-marker-115548254600u9yjx6qhj.png',
            iconSize: [38, 38], // size of the icon
            iconAnchor: [22, 94], // point of the icon which will correspond to marker's location
            popupAnchor: [-3, -76] // point from which the popup should open relative to the iconAnchor
        });

        L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
            detectRetina: true,
            maxZoom: 20,
            maxNativeZoom: 17,
            attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
        }).addTo(this.map);

        axios({
            method: 'GET',
            url: apiUrls.ORDERS.track + this.props.match.params.order,
            headers: {
                Authorization: authHeader()
            }
        }).then(result => {
            if (result.status === 200) {
                if(result.status === 200){
                    const orderData = result.data.data;
                    if(orderData.delivery_location){
                        const lat = parseFloat(orderData.delivery_location.latitude);
                        const long = parseFloat(orderData.delivery_location.longitude);

                        this.setState({
                            destMarker: L.marker([lat, long], { icon: endIcon }).addTo(this.map).bindPopup("Order delivery location.")
                        })
                    } else if(!orderData.delivery_location){
                        this.setState({
                            deliveryLocationMessage: 'No delivery location found for this order'
                        })
                    }

                    if(orderData.delivery_man){
                        const deliveryBoyDetails = orderData.delivery_man;
                        if(deliveryBoyDetails.latitude && deliveryBoyDetails.longitude){
                            const lat = parseFloat(deliveryBoyDetails.latitude);
                            const long = parseFloat(deliveryBoyDetails.longitude);
                            const imageSrc = deliveryBoyDetails.image ? (ApiUrlHost + '/' + deliveryBoyDetails.image) : ProfileDef;
                            this.setState({
                                movementMarker: L.marker([lat, long], { icon: startIcon }).addTo(this.map).bindPopup("<img src='"+  imageSrc  +"' height='20' width='20' /> <span>"+ deliveryBoyDetails.firstname +" ("+ getTypeName(deliveryBoyDetails.emptype) +")</span>").openPopup(),
                                deliveryManMessage: ''
                            })
                            this.map.setView([lat, long],12);    
                        } else {
                            this.setState({
                                deliveryManMessage: 'Delivery man seems offline'
                            })
                        }

                        
                    } else if(!orderData.delivery_man){
                        this.setState({
                            deliveryManMessage: 'No delivery man assigned for this order'
                        })
                    }

                }

            }
        }).catch(e => {
            console.log(e)
        });
    }

    componentWillUnmount() {
        socket.off("location_change", this.getData);
    }

    render() {

        return (
            <div className="content">
                <Grid fluid>
                    <h3>Delivery Tracking</h3>
                    {this.state.deliveryManMessage && <p>{this.state.deliveryManMessage}</p>}
                    {this.state.deliveryLocationMessage && <p>{this.state.deliveryLocationMessage}</p>}
                    
                    <div className="map-container" id="map" style={{ height: '500px' }}>
                    </div>
                </Grid>

            </div>
        );
    }
}

export default TrackingUser;
