    getOneData(_status, _categories, _products) {
        if (this.state.oneBillid) {
            this.setState({
                oneBillOrder: [],
                liveLoader: true,
            });
            this.setState({
                showOrderView: true
            })
            var params = {};


            if (_status) {
                params.currBillStatus = _status
            } else if (this.state.currBillStatus) {
                params.currBillStatus = this.state.currBillStatus
            }

            if (_categories) {
                params.category = _categories;
            } else if (this.state.selectedCategories2.length > 0) {
                params.category = this.state.selectedCategories2;
            }

            if (_products) {
                params.filterProducts = _products;
            } else if (this.state.selectedProducts2) {
                params.filterProducts = this.state.selectedProducts2;
            }


            // if (_createdDate) {
            //     params.createdDate = _createdDate
            // }

            // if (_createdDateTo) {
            //     params.createdDateEnd = _createdDateTo
            // }

            // if (_deliveryDate) {
            //     params.deliveryDate = _deliveryDate
            // }

            // if (_deliveryDateTo) {
            //     params.deliveryDateTo = _deliveryDateTo
            // }

            if (this.state.createdDate) {
                params.createdDate = this.state.createdDate
            }

            if (this.state.createdDateTo) {
                params.createdDateEnd = this.state.createdDateTo
            }

            if (this.state.deliveryDate) {
                params.deliveryDate = this.state.deliveryDate
            }

            if (this.state.deliveryDateTo) {
                params.deliveryDateTo = this.state.deliveryDateTo
            }

            axios({
                method: 'GET',
                url: apiUrls.ORDERS.oneStockBill + '/' + this.state.oneBillid,
                headers: {
                    Authorization: authHeader()
                },
                params: params
            }).then(result => {

                if (result.status === 200 && result.data.data) {
                    result.data.data[0].pastry.sort(function (o1, o2) {
                        return new Date(o1.delivery_date) - new Date(o2.delivery_date);
                    });

                    let respData = result.data.data;
                    let _tempOrder = [];
                    respData[0].pastries.forEach(item => {
                        item.data.total = parseFloat(item.data.total);
                        _tempOrder.push(item)
                    })

                    _tempOrder = _.orderBy(_tempOrder, 'data.total', ['asc']); // Use Lodash to sort array by 'name'

                    respData[0].pastries = _tempOrder;

                    this.setState({
                        oneBillOrder: respData,
                        liveLoader: false,
                        stockOrderPayment: result.data.payment ? result.data.payment : null
                    });
                } else {
                    this.setState({
                        oneBillOrder: [],
                        liveLoader: false,
                        stockOrderPayment: null
                    });
                }
            }).catch(e => {
                this.setState({
                    oneBillOrder: [],
                    liveLoader: false,
                    stockOrderPayment: null
                });
            });
        }
    }
