
import React, { Component } from "react";
import { Link } from "react-router-dom";
import { FormGroup, FormControl, Row, Col, Button } from "react-bootstrap";
import ReactPaginate from 'react-paginate';

export class Card extends Component {

  render() {
    return (
      <div className={"card" + (this.props.plain ? " card-plain" : "")}>
        <div className={"header" + (this.props.hCenter ? " text-center" : "")}>
          <Row>
            <Col md={(this.props.empSearch || this.props.productSearch || this.props.orderSearch) ? 2 : 6}>
              <h4 className="title">{this.props.title}</h4>
              <p className="category">{this.props.category}</p>
            </Col>
            <Col md={(this.props.empSearch || this.props.productSearch || this.props.orderSearch) ? 10 : 6}>
              {
                this.props.search && (
                  <Row>
                    <Col md={(this.props.empSearch || this.props.productSearch) ? 4 : 8}>
                      <FormGroup>
                        <FormControl type="text"
                          inputRef={(ref) => { this.input = ref }}
                          placeholder={this.props.searchplaceholder}
                          onChange={() => this.props.searchCall(this.input.value)} />
                      </FormGroup>
                    </Col>
                    {
                      this.props.empSearch && (
                        <Col md={4}>
                          <FormGroup>
                            <FormControl type="text"
                              componentClass="select"
                              inputRef={(ref) => { this.branch = ref }}
                              onChange={() => this.props.searchCallByBrnach(this.branch.value)}>
                              <option value="">Branch</option>
                              {this.props.storesCol.map((store) => {
                                return (
                                  <option value={store._id} key={store._id}>{store.branch}</option>
                                )
                              })}
                            </FormControl>
                          </FormGroup>
                        </Col>

                      )
                    }

                    {
                      this.props.empSearch && (
                        <Col md={2}>

                          <FormGroup>
                            <FormControl type="text"
                              componentClass="select"
                              inputRef={(ref) => { this.type = ref }}
                              onChange={() => this.props.searchCallByType(this.type.value)}>
                              <option value="">Type</option>
                              {this.props.typeOfemp.map((type) => {
                                return (
                                  <option value={type.id} key={type.id}>{type.name}</option>
                                )
                              })}
                            </FormControl>
                          </FormGroup>
                        </Col>

                      )
                    }

                    {
                      this.props.productSearch && (
                        <Col md={4}>
                          <FormGroup>
                            <FormControl type="text"
                              componentClass="select"
                              inputRef={(ref) => { this.branch = ref }}
                              onChange={() => this.props.searchCallByCate(this.branch.value)}>
                              <option value="">Category</option>
                              {this.props.catCollection.map((store) => {
                                return (
                                  <option value={store._id} key={store._id}>{store.name}</option>
                                )
                              })}
                            </FormControl>
                          </FormGroup>
                        </Col>

                      )
                    }
                    {
                      this.props.productSearch && (
                        <Col md={2}>

                          <FormGroup>
                            <FormControl type="text"
                              componentClass="select"
                              inputRef={(ref) => { this.type = ref }}
                              onChange={() => this.props.searchCallByAlbum(this.type.value)}>
                              <option value="">Album</option>
                              {this.props.albumCollection.map((type) => {
                                return (
                                  <option value={type._id} key={type._id}>{type.name}</option>
                                )
                              })}
                            </FormControl>
                          </FormGroup>
                        </Col>

                      )
                    }
                    <Col md={2}>
                      <Link className="btn btn-default" to={this.props.createLink}>Add</Link>
                    </Col>
                  </Row>
                )
              }
              {(this.props.orderSearch && !this.props.noStatusSearch) && <Col md={2}>
                <FormGroup>
                  <label>Status</label>

                  <FormControl type="text"
                    componentClass="select"
                    inputRef={(ref) => { this.statusOrder = ref }}
                    onChange={() => this.props.searchCallStatus(this.statusOrder.value)}>
                    <option value="">Status</option>
                    <option value="1">Ordered</option>
                    <option value="2">Cancelled</option>
                    <option value="4">Preparing</option>
                    <option value="5">Ready</option>
                    <option value="6">Picked</option>
                    <option value="7">Delivered</option>
                    <option value="8">Not Delivered</option>
                    <option value="3">Completed</option>
                  </FormControl>
                </FormGroup>
              </Col>}

              {
                this.props.branchHeadSearch && (
                  <Col md={3}>
                    <FormGroup>
                      <FormControl type="text"
                        componentClass="select"
                        inputRef={(ref) => { this.branchHead = ref }}
                        onChange={() => this.props.searchByBranchEmp(this.branchHead.value)}>
                        <option value="">All Branch</option>
                        {this.props.empList.map((store) => {
                          return (
                            <option value={store._id} key={store._id}>{store.firstname}</option>
                          )
                        })}
                      </FormControl>
                    </FormGroup>
                  </Col>

                )
              }
              {
                this.props.branchHeadSearch && (
                  <Col md={3}>
                    <FormGroup>
                      <label>Category</label>

                      <FormControl type="text"
                        componentClass="select"
                        inputRef={(ref) => { this.branchHeadCategory = ref }}
                        onChange={() => this.props.searchCallByCategory(this.branchHeadCategory.value)}>
                        <option value="">All Category</option>
                        {this.props.categoryCol.map((store) => {
                          return (
                            <option value={store._id} key={store._id}>{store.name}</option>
                          )
                        })}
                      </FormControl>
                    </FormGroup>
                  </Col>

                )
              }
              {(this.props.orderSearch && !this.props.noStatusSearch) && <Col md={2}>
                <FormGroup>
                  <label>Branch</label>

                  <FormControl type="text"
                    componentClass="select"
                    inputRef={(ref) => { this.branchOrder = ref }}
                    onChange={() => this.props.searchCallBranch(this.branchOrder.value)}>
                    <option value="">Branch</option>
                    {this.props.branchesList.map((store) => {
                      return (
                        <option value={store._id} key={store._id}>{store.branch}</option>
                      )
                    })}
                  </FormControl>
                </FormGroup>
              </Col>}

              {(this.props.orderSearch) && <Col md={3}>
                <FormGroup>
                  <label>Order Date From
                  {(this.branchDateOrder && this.branchDateOrder.value) && (<span style={{ color: 'tomato' }} onClick={() => {
                      this.branchDateOrder.value = '';
                      this.props.searchByDate();
                    }}> <i className="fa fa-times-circle fa-2x" /></span>)}

                  </label>

                  <FormControl type="date"
                    inputRef={(ref) => { this.branchDateOrder = ref }}
                    onChange={() => this.props.searchByDate(this.branchDateOrder.value)}>
                  </FormControl>
                </FormGroup>
              </Col>}
              {(this.props.orderSearch) && <Col md={3}>
                <FormGroup>
                  <label>Order Date To
                  {(this.branchDateOrderTo && this.branchDateOrderTo.value) && (<span style={{ color: 'tomato' }} onClick={() => {
                      this.branchDateOrderTo.value = '';
                      this.props.searchByDateUpTo();
                    }}> <i className="fa fa-times-circle fa-2x" /></span>)}

                  </label>

                  <FormControl type="date"
                    inputRef={(ref) => { this.branchDateOrderTo = ref }}
                    onChange={() => this.props.searchByDateUpTo(this.branchDateOrderTo.value)}>
                  </FormControl>
                </FormGroup>
              </Col>}

              {(this.props.orderSearch && !this.props.noStatusSearch) && <Col md={3}>
                <FormGroup>
                  <label>
                    Delivery Date From
                  {(this.branchDelDateOrder && this.branchDelDateOrder.value) && (<span style={{ color: 'tomato' }} onClick={() => {
                      this.branchDelDateOrder.value = '';
                      this.props.searchByDeliveryDate();
                    }}> <i className="fa fa-times-circle fa-2x" /></span>)}

                  </label>

                  <FormControl type="date"
                    inputRef={(ref) => { this.branchDelDateOrder = ref }}
                    onChange={() => this.props.searchByDeliveryDate(this.branchDelDateOrder.value)}>
                  </FormControl>
                </FormGroup>

              </Col>}
              {(this.props.orderSearch && !this.props.noStatusSearch) && <Col md={3}>
                <FormGroup>
                  <label>
                    Delivery Date To
                  {(this.branchDelDateOrderTo && this.branchDelDateOrderTo.value) && (<span style={{ color: 'tomato' }} onClick={() => {
                      this.branchDelDateOrderTo.value = '';
                      this.props.searchByDeliveryDateTo();
                    }}> <i className="fa fa-times-circle fa-2x" /></span>)}

                  </label>

                  <FormControl type="date"
                    inputRef={(ref) => { this.branchDelDateOrderTo = ref }}
                    onChange={() => this.props.searchByDeliveryDateTo(this.branchDelDateOrderTo.value)}>
                  </FormControl>
                </FormGroup>

              </Col>}

              {this.props.orderSearch && <Col md={2}>
                <Button onClick={this.props.downloadReport} className="mar-t-25px">Download</Button>
              </Col>}
            </Col>
          </Row>

        </div>
        <div
          className={
            "content" +
            (this.props.ctAllIcons ? " all-icons" : "") +
            (this.props.ctTableFullWidth ? " table-full-width" : "") +
            (this.props.ctTableResponsive ? " table-responsive" : "") +
            (this.props.ctTableUpgrade ? " table-upgrade" : "")
          }
        >
          {this.props.content}

          <div className="footer text-center">
            {this.props.legend}
            {this.props.stats != null ? <hr /> : ""}
            <div className="stats">
              <i className={this.props.statsIcon} /> {this.props.stats}
            </div>

            {
              (this.props.pagination && this.props.totalPages > 0) && (

                // <div className="page-btn-wrap">
                //   <button className="btn-navg" onClick={()=>this.props.prev()}>Prev</button>

                //   {
                //     [...Array(this.props.totalPages)].map((e,index) => {
                //       return (
                //         <button key={index + '-' + Math.random()} className={this.props.currentPage == (index) ? "page-btns active" : "page-btns"} onClick={()=>this.props.processPagination(index)}>{index + 1}</button>
                //       )
                //     })
                //   }
                //   <button className="btn-navg" onClick={()=>this.props.next()}>Next</button>
                // </div>
                <ReactPaginate
                  previousLabel={'previous'}
                  initialPage={this.props.currentPage}
                  nextLabel={'next'}
                  breakLabel={'...'}
                  breakClassName={'break-me'}
                  pageCount={this.props.totalPages}
                  marginPagesDisplayed={2}
                  pageRangeDisplayed={5}
                  onPageChange={(index) => this.props.processPagination(index.selected)}
                  containerClassName={'pagination'}
                  subContainerClassName={'pages pagination'}
                  activeClassName={'active'}
                />


              )
            }
          </div>

        </div>
      </div>
    );
  }
}

export default Card;
