import React, { Component } from "react";
import {
  FormGroup,
  FormControl,
  Row,
  Grid,
  Col,
  Table,
  Button,
} from "react-bootstrap";
import axios from "axios";
import NotificationSystem from "react-notification-system";
import ReactPaginate from "react-paginate";
import * as moment from "moment";

import { style } from "../../variables/Variables.jsx";
import "../../assets/css/custom.css";
import { authHeader } from "../../configs/helpers";
import { apiUrls } from "../../configs/configs";
import { Multiselect } from "multiselect-react-dropdown";
import ReturnOrderPreview from "../../components/PopUps/ReturnPrint";

class ReturnOrders extends Component {
  constructor(props) {
    super(props);
    this.state = {
      searchbranch: "",
      returnDateFrom: "",
      returnDateTo: "",
      currentPage: 0,
      branches: [],
      searchLoad: false,
      searchRecords: [],
      totalSearchRec: 0,
      viewOne: false,
      oneItem: null,
      returnInputRef: [],
      selectedCategories: [],
      productsByCategory: [],
      selectedProducts: [],
      categories: [],
      openPrintModal: false,
      printData: [],
      printLoader: false,
      printData: null,
      branchName: '',
      selectedBranchesList: [],
      branchMobile: "",
    };
  }

  componentWillMount() {
    this.getAllBranchEmployees();
    this.getAllRecords();
    this.getCategoryList();
  }

  closePrintPopup() {
    this.setState({
      openPrintModal: false,
    });
  }

  getCategoryList() {
    axios({
      method: "GET",
      url: apiUrls.PRODUCT.getAllCategoryPastry,
      headers: {
        Authorization: authHeader(),
      },
    })
      .then((result) => {
        if (result.status === 200) {
          this.setState({
            categories: result.data.data,
          });
        } else {
          this.setState({
            categories: [],
          });
        }
      })
      .catch((e) => {
        this.setState({
          categories: [],
        });
      });
  }

  getAllBranchEmployees() {
    axios({
      method: "GET",
      url: apiUrls.BRANCH_EMPLOYEE_LIST,
      headers: {
        Authorization: authHeader(),
      },
    })
      .then((result) => {
        if (result.status === 200 && result.data.data) {
          this.setState({
            branches: result.data.data,
            selectedBranchesList: result.data.data
          });
        } else {
          this.setState({
            branches: [],
          });
        }
      })
      .catch((e) => {
        this.setState({
          branches: [],
        });
      });
  }
  getPaginateRec(index) {
    this.setState(
      {
        currentPage: index,
      },
      () => {
        this.getAllRecords();
      }
    );
  }

  getAllRecords() {
    this.setState({
      searchLoad: true,
    });

    var params = {
      page: this.state.currentPage,
    };

    if (this.state.searchbranch) {
      params.branch = this.state.searchbranch;
    }
    if (this.state.returnDateFrom) {
      params.returnDateFrom = this.state.returnDateFrom;
    }

    if (this.state.returnDateTo) {
      params.returnDateTo = this.state.returnDateTo;
    }

    if (this.state.selectedCategories.length > 0) {
      params.category = this.state.selectedCategories;
    }

    if (this.state.selectedProducts.length > 0) {
      params.filterProducts = this.state.selectedProducts;
    }

    axios({
      method: "GET",
      url: apiUrls.REPORTS.returnOrder,
      headers: {
        Authorization: authHeader(),
      },
      params: params,
    })
      .then((result) => {
        if (result.status === 200 && result.data.data && result.data.data[0]) {
          if (this.state.oneItem) {
            const _tempData = result.data.data[0].paginatedResults;
            _tempData.forEach((_n) => {
              if (_n._id == this.state.oneItem._id) {
                this.setState({
                  oneItem: _n,
                });
              }
            });
          }
          this.setState({
            searchRecords: result.data.data[0].paginatedResults,
            searchLoad: false,
            totalSearchRec: result.data.data[0].totalCount[0].count,
          });
        } else {
          this.setState({
            searchRecords: [],
            searchLoad: false,
          });
        }
      })
      .catch((e) => {
        this.setState({
          searchRecords: [],
          searchLoad: false,
        });
      });
  }

  setCreateData(e) {
    this.setState(
      {
        returnDateFrom: e.target.value,
      },
      () => {
        this.getAllRecords();
      }
    );
  }

  setCreateDataTo(e) {
    this.setState(
      {
        returnDateTo: e.target.value,
      },
      () => {
        this.getAllRecords();
      }
    );
  }

  getTotalItems(item) {
    let total = 0;
    item.pastry.forEach((element) => {
      element.qty.forEach((one) => {
        if (one && one.items) total = parseFloat(total) + parseFloat(one.items);
      });
    });
    return total;
  }

  viewOneItem(item) {
    this.setState({
      inputRef: [],
      viewOne: true,
      oneItem: item,
    });
  }

  getQtyStatus(item) {
    let className = "return-bill-complete";
    item.qty.forEach((one) => {
      if (one.confirmed === false) {
        className = "bill-incomplete";
      }
    });
    return className;
  }

  getQtyTotal(item) {
    let total = 0;
    item.qty.forEach((one) => {
      total = parseFloat(total) + parseFloat(one.items);
    });
    return total;
  }

  confirmReturn(returnId, pastryId, item, _qty) {
    var _notificationSystem = this.refs.notificationSystem;
    const sendData = {
      pastry: pastryId,
      qty: _qty.value,
    };

    axios({
      method: "POST",
      url: apiUrls.REPORTS.returnOrder + "/" + returnId,
      data: sendData,
      headers: {
        "Content-Type": "application/json",
        Authorization: authHeader(),
      },
    })
      .then((result) => {
        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-check" />,
          message: <div>updated</div>,
          level: "success",
          position: "tr",
          autoDismiss: 15,
        });
        this.getAllRecords();
      })
      .catch((e) => {
        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-close-circle" />,
          message: (
            <div>
              {e.response ? e.response.data.message : "Something went wrong!"}
            </div>
          ),
          level: "error",
          position: "tr",
          autoDismiss: 15,
        });
      });
  }

  getAllProductsByCategory(category) {
    if (category && category.length > 0) {
      axios({
        method: "GET",
        url: apiUrls.PRODUCT.getAllProductByCategory,
        headers: {
          Authorization: authHeader(),
        },
        params: { categories: category },
      })
        .then((result) => {
          if (result.status === 200) {
            this.setState({
              productsByCategory: result.data.data,
            });
          } else {
            this.setState({
              productsByCategory: [],
            });
          }
        })
        .catch((e) => {
          this.setState({
            productsByCategory: [],
          });
        });
    } else {
      this.setState({
        productsByCategory: [],
      });
    }
  }

  categorySelection(selectedList) {
    const tempSelected = [];
    selectedList.forEach((item) => {
      tempSelected.push(item._id);
    });
    this.getAllProductsByCategory(tempSelected);

    this.setState(
      {
        selectedCategories: tempSelected,
      },
      () => {
        this.getAllRecords();
      }
    );
  }

  productSelection(selectedList) {
    const tempSelected = [];
    selectedList.forEach((item) => {
      tempSelected.push(item._id);
    });
    this.setState(
      {
        selectedProducts: tempSelected,
      },
      () => {
        this.getAllRecords();
      }
    );
  }

  getPrintRec() {
    this.setState({
      openPrintModal: true,
      printLoader: true,
    });

    var params = {
      page: this.state.currentPage,
    };

    if (this.state.searchbranch) {
      params.branch = this.state.searchbranch;
    }
    if (this.state.returnDateFrom) {
      params.returnDateFrom = this.state.returnDateFrom;
    }

    if (this.state.returnDateTo) {
      params.returnDateTo = this.state.returnDateTo;
    }

    if (this.state.selectedCategories.length > 0) {
      params.category = this.state.selectedCategories;
    }

    if (this.state.selectedProducts.length > 0) {
      params.filterProducts = this.state.selectedProducts;
    }

    let branchName = '';

    if (this.state.searchbranch) {
      params.branch = this.state.searchbranch;
      this.state.branches.forEach((i) => {
        if (i._id == this.state.searchbranch) {
          branchName = i.firstname;
        }
      })
    }
    this.setState({
      branchName: branchName
    })

    axios({
      method: "GET",
      url: apiUrls.ORDERS.printReturnOrders,
      headers: {
        Authorization: authHeader(),
      },
      params: params,
    })
      .then((result) => {
        if (
          result.status === 200 &&
          result.data.data &&
          result.data.data.length > 0
        ) {
          const printData = result.data.data;
          this.setState({
            printData: printData,
            printLoader: false,
          });
        } else {
          this.setState({
            printData: [],
            printLoader: false,
          });
        }
      })
      .catch((e) => {
        console.log(e);
        this.setState({
          printData: [],
          printLoader: false,
        });
      });
  }

  getTotal() {
    let total = 0;
    this.state.searchRecords.forEach(item => {
      item.pastry.forEach((element) => {
        element.qty.forEach((one) => {
          if (one && one.items) total = parseFloat(total) + parseFloat(one.items);
        });
      });
    })
    return total;
  }


  render() {
    return (
      <div className="content">
        <NotificationSystem ref="notificationSystem" style={style} />
        <ReturnOrderPreview
          closePopup={() => this.closePrintPopup()}
          open={this.state.openPrintModal}
          loader={this.state.printLoader}
          branches={this.state.selectedBranchesList}
          data={this.state.printData}
          dateFilter={{
            orderFrom: this.state.returnDateFrom,
            orderTo: this.state.returnDateTo
          }}
          phone={this.state.branchMobile}
          branchName={this.state.branchName}
        />
        <Grid fluid>
          <Row>
            <Col md={2}>
              <FormGroup>
                <label>Choose Branch</label>

                <FormControl
                  type="text"
                  componentClass="select"
                  inputRef={(ref) => {
                    this._sbranch = ref;
                  }}
                  onChange={() => {
                    let br = this.state.branches;
                    let mb = '';

                    if (this._sbranch.value) {
                      br = this.state.branches.filter((i) => {
                        return i._id == this._sbranch.value
                      })
                    }
                    this.state.branches.forEach(i => {
                      if (i._id == this._sbranch.value) {
                        mb = i.phone
                      }
                    })

                    this.setState({ searchbranch: this._sbranch.value, selectedBranchesList: br, branchMobile: mb }, () => {
                      this.getAllRecords();
                    })
                  }
                  }
                >
                  <option value="">All</option>
                  {this.state.branches.map((store) => {
                    return (
                      <option value={store._id} key={store._id}>
                        {store.firstname}
                      </option>
                    );
                  })}
                </FormControl>
              </FormGroup>
            </Col>

            <Col md={2}>
              <FormGroup>
                <label>
                  Return Date From
                  {this.createDate && this.createDate.value && (
                    <span
                      style={{ color: "tomato", fontSize: 8 }}
                      onClick={() => {
                        this.createDate.value = "";
                        this.setState(
                          { returnDateFrom: this.createDate.value },
                          () => {
                            this.getAllRecords();
                          }
                        );
                      }}
                    >
                      {" "}
                      <i className="fa fa-times-circle fa-2x" />
                    </span>
                  )}
                </label>
                <FormControl
                  type="date"
                  inputRef={(ref) => {
                    this.createDate = ref;
                  }}
                  onChange={(e) => this.setCreateData(e)}
                ></FormControl>
              </FormGroup>
            </Col>
            <Col md={2}>
              <FormGroup>
                <label>
                  Return Date To
                  {this.createDateTo && this.createDateTo.value && (
                    <span
                      style={{ color: "tomato", fontSize: 8 }}
                      onClick={() => {
                        this.createDateTo.value = "";
                        this.setState(
                          { returnDateTo: this.createDateTo.value },
                          () => {
                            this.getAllRecords();
                          }
                        );
                      }}
                    >
                      {" "}
                      <i className="fa fa-times-circle fa-2x" />
                    </span>
                  )}
                </label>
                <FormControl
                  type="date"
                  inputRef={(ref) => {
                    this.createDateTo = ref;
                  }}
                  onChange={(e) => this.setCreateDataTo(e)}
                ></FormControl>
              </FormGroup>
            </Col>
          </Row>
          <Row>
            <Col md={4}>
              <FormGroup>
                <label>Categories</label>
                <Multiselect
                  options={this.state.categories} // Options to display in the dropdown
                  // selectedValues={this.state.selectedValue} // Preselected value to persist in dropdown
                  onSelect={this.categorySelection.bind(this)} // Function will trigger on select event
                  onRemove={this.categorySelection.bind(this)} // Function will trigger on remove event
                  displayValue="name" // Property name to display in the dropdown options
                />
              </FormGroup>
            </Col>
            <Col md={4}>
              <FormGroup>
                <label>Products</label>
                <Multiselect
                  options={this.state.productsByCategory} // Options to display in the dropdown
                  // selectedValues={this.state.selectedValue} // Preselected value to persist in dropdown
                  onSelect={this.productSelection.bind(this)} // Function will trigger on select event
                  onRemove={this.productSelection.bind(this)} // Function will trigger on remove event
                  displayValue="name" // Property name to display in the dropdown options
                />
              </FormGroup>
            </Col>

            <Col md={3} className="mar-t-25px">
              <Button
                variant="dark"
                className="export-btn"
                onClick={() => this.getPrintRec()}
              >
                <i className="fa fa-print"></i> Print Preview
              </Button>
            </Col>
          </Row>
          <Table
            responsive
            bordered
            hover
            ref={(el) => (this.componentRefPending = el)}
          >
            <thead>
              <tr>
                <th>S.NO</th>
                <th>Branch</th>
                <th>Return Date</th>
                <th>Total Return items</th>
                <th>View Items</th>
              </tr>
            </thead>
            <tbody>
              {this.state.searchLoad === true && (
                <tr>
                  <td colSpan={5}>Loading...</td>
                </tr>
              )}
              {this.state.searchRecords.length > 0 &&
                this.state.searchLoad === false &&
                this.state.searchRecords.map((returnItems, key) => {
                  return (
                    <tr key={(key + 1) * 123}>
                      <td>{key + 1}</td>
                      <td>
                        {returnItems.employees
                          ? returnItems.employees.firstname
                          : "-"}
                      </td>
                      <td>
                        {moment(returnItems.return_date).format("DD/MM/YYYY")}
                      </td>
                      <td>
                        {returnItems.pastry
                          ? this.getTotalItems(returnItems)
                          : 0}
                      </td>
                      <td style={{ textAlign: "center" }}>
                        <i
                          className="fa fa-eye"
                          onClick={() => this.viewOneItem(returnItems)}
                        ></i>
                      </td>
                    </tr>
                  );
                })}
              {this.state.searchRecords.length > 0 &&
                <tr>
                  <td style={{ fontWeight: 'bold' }} colSpan={3}>Total</td>
                  <td>{this.getTotal()}</td>
                </tr>}

              {this.state.searchRecords.length === 0 &&
                this.state.searchLoad === false && (
                  <tr>
                    <td colSpan={5}>No orders found</td>
                  </tr>
                )}
            </tbody>
          </Table>
          <div className="footer text-center">
            <ReactPaginate
              previousLabel={"previous"}
              nextLabel={"next"}
              breakLabel={"..."}
              breakClassName={"break-me"}
              pageCount={Math.ceil(this.state.totalSearchRec / 15)}
              marginPagesDisplayed={2}
              pageRangeDisplayed={8}
              onPageChange={(index) => this.getPaginateRec(index.selected)}
              containerClassName={"pagination"}
              subContainerClassName={"pages pagination"}
              activeClassName={"active"}
              phone={this.state.branchMobile}
            />
          </div>
          {this.state.viewOne === true && (
            <div>
              <p>
                Return items from{" "}
                {this.state.oneItem && this.state.oneItem.employees
                  ? this.state.oneItem.employees.firstname
                  : "-"}{" "}
                branch on{" "}
                {this.state.oneItem && this.state.oneItem.return_date
                  ? moment(this.state.oneItem.return_date).format("DD/MM/YYYY")
                  : "-"}
              </p>
              <Table responsive bordered hover>
                <thead>
                  <tr>
                    <th>#</th>
                    <th>Products</th>
                    <th>Unit price</th>
                    <th>Return Qty</th>
                  </tr>
                </thead>
                <tbody>
                  {this.state.oneItem &&
                    this.state.oneItem.pastry.length > 0 &&
                    this.state.oneItem.pastry.map((item, key) => {
                      return (
                        <tr key={item._id}>
                          <td>{key + 1}</td>
                          <td>
                            {item.pastryDetails && item.pastryDetails[0]
                              ? item.pastryDetails[0].name
                              : "-"}
                          </td>
                          <td>
                            ₹{" "}
                            {item.pastryDetails && item.pastryDetails[0]
                              ? item.pastryDetails[0].price
                              : "-"}
                          </td>
                          <td className={this.getQtyStatus(item)}>
                            <div className="flex-row">
                              <input
                                type="number"
                                defaultValue={this.getQtyTotal(item)}
                                ref={(el) =>
                                  (this.state.returnInputRef[key] = el)
                                }
                              />
                              <button
                                onClick={() =>
                                  this.confirmReturn(
                                    this.state.oneItem._id,
                                    item.p_id,
                                    item.qty,
                                    this.state.returnInputRef[key]
                                  )
                                }
                              >
                                <i className="fa fa-check"></i>
                              </button>
                              {item.qty.length > 1 &&
                                item.qty.map((oneQ, key) => {
                                  if (key > 0) {
                                    return (
                                      <span
                                        style={{ color: "#fff" }}
                                        key={oneQ._id}
                                      >
                                        (<i className="fa fa-arrow-up"></i>{" "}
                                        {oneQ.items})
                                      </span>
                                    );
                                  }
                                })}
                            </div>
                          </td>
                        </tr>
                      );
                    })}
                </tbody>
              </Table>
            </div>
          )}
        </Grid>
      </div>
    );
  }
}

export default ReturnOrders;
