
import React, { Component } from "react";
import { Grid, Row, Col } from "react-bootstrap";
import L from 'leaflet';
import axios from 'axios';
import 'leaflet/dist/leaflet.css';
import Marker from './../assets/img/pin.png';
import ProfileDef from './../assets/img/default-avatar.png';
import { authHeader,getTypeName } from '../configs/helpers';
import { ApiUrlHost, apiUrls, SOCKETURL } from '../configs/configs';
import socketIOClient from "socket.io-client";
const convert = require('xml-js');
const socket = socketIOClient(SOCKETURL);

class TrackingUserList extends Component {
    map;
    constructor(props){
        super(props);
        this.state = {
            mapMarker: null,
            totalEmployees: 0,
            activeEmployees: 0,
            activeUserid: '',
            allEmployeeList: []
        }
    }

    componentDidMount() {
        this.map = L.map('map', {
            zoom: 4,
            center: [8.7642, 78.1348]
        });
            
        this.getAllEmployeeList()

        socket.on("location_change", ()=>{
            this.getAllEmployeeList()
        });


    }

    getAllEmployeeList(){
        L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
            detectRetina: true,
            maxZoom: 20,
            maxNativeZoom: 17,
            attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
        }).addTo(this.map);

        axios({
            method: 'GET',
            url: apiUrls.EMPLOYEE_LOCATION,
            headers: {
              Authorization: authHeader()
            }
          }).then(result => {
              if(result.status === 200){

                const e_data = result.data.data;
                  if(e_data && e_data.length > 0){
                    const totalEmp = e_data.length;
                    const activeEmp = [];
                    const tempEmp = [];

                    e_data.map((data) => {
                        if(data.latitude && data.longitude){
                            activeEmp.push({
                                coOrds: [parseFloat(data.latitude), parseFloat(data.longitude)],
                                pic: data.image ? ApiUrlHost + '/' + data.image : ProfileDef,
                                name: data.firstname,
                                role: getTypeName(data.emptype)
                            })
                        }
                        tempEmp.push({
                            name: data.firstname,
                            type: getTypeName(data.emptype),
                            photo: data.image ? ApiUrlHost + '/' + data.image : ProfileDef,
                            latitude: data.latitude,
                            longitude: data.longitude,
                            id: data._id
                        })
                    });

                    if(this.state.activeUserid){
                        tempEmp.forEach(user => {
                            if(user.id === this.state.activeUserid){
                                this.setMapMarker(user);
                            }
                        })
                    }


                    this.setState({
                        activeEmployees: activeEmp.length,
                        totalEmployees: totalEmp,
                        allEmployeeList: tempEmp
                    });
                  }
              }
          }).catch(e => {
            console.log(e)
          });
    }

    setMapMarker(info) {

        this.setState({
            activeUserid: info.id
        });

        if(this.state.mapMarker){
            this.map.removeLayer(this.state.mapMarker);
        }

        if(info.latitude && info.longitude){
            info.address = 'Could not fetch address';

            axios({
                method: 'GET',
                url: 'https://nominatim.openstreetmap.org/reverse?lat='+info.latitude+'&&lon=' + info.longitude
              }).then(result => {
                  if(result.status == 200 && result.data){
                    var result1 = convert.xml2json(result.data, {compact: false, spaces: 4});
                    var parseContent = JSON.parse(result1);
                    if(parseContent && parseContent.elements[0] && parseContent.elements[0].elements[0] && parseContent.elements[0].elements[0].elements[0] &&parseContent.elements[0].elements[0].elements[0].text){
                        info.address = parseContent.elements[0].elements[0].elements[0].text;
                        this.setMarker(info)
                    } else{
                        this.setMarker(info)
                    }
                  } else {
                    this.setMarker(info)
                  }
              }).catch(e => {
                console.log(e)
                this.setMarker(info)
              });
        }
    }

    setMarker(info){
        const coOrds = [parseFloat(info.latitude), parseFloat(info.longitude)];

        const startIcon = L.icon({
            iconUrl: Marker, //'https://toppng.com/public/uploads/preview/eat-play-do-icon-map-marker-115548254600u9yjx6qhj.png',
            iconSize: [38, 38], // size of the icon
            iconAnchor: [22, 94], // point of the icon which will correspond to marker's location
            popupAnchor: [-3, -76] // point from which the popup should open relative to the iconAnchor
        });

        this.setState({
            mapMarker: L.marker(coOrds, { icon: startIcon }).addTo(this.map).bindPopup("<img src='"+info.photo+"'border-radius='10px' height='20' width='20'  style='border-radius: 10px;' /> <span style='font-weight: 600;'>"+ info.name +"</span><p style='font-size: 12px;'>"+ info.address +"</p>").openPopup()
        });
        this.map.setView(coOrds, 14);    

    }

    componentWillUnmount() {
        socket.off("location_change", this.getData);
    }

    render() {

        return (
            <div className="content">
                <Grid fluid>
                    <h3>Employees Tracking</h3>
                    <p>Total Employees: {this.state.totalEmployees}</p>
                    <p>Active Employees: {this.state.activeEmployees}</p>
                    <Row>
                        <Col md={4}>
                            <div className="employee-Lists-wrap">
                            <ul className="employee-list">
                                {this.state.allEmployeeList.length > 0 && (
                                    this.state.allEmployeeList.map(employee => {
                                        return (<li className="employee-data" key={Math.random()} onClick={() => this.setMapMarker(employee)}>
                                        <div className="flex-items">
                                            <img src={employee.photo} alt="profile"/>
                                            <span className={employee.latitude && employee.longitude ? "online" : "offline"}></span>
    
                                            <div className="info-user">
                                                <p>{employee.name}</p>
                                                <p>{employee.type}</p>
                                            </div>
                                        </div>
                                    </li>)
                                    })
                                )}
                                

                            </ul>
                        </div>
                        </Col>
                        <Col md={8}>
                            <div className="map-container" id="map" style={{ height: '450px' }}>
                            </div>
                        </Col>
                    </Row>
                    

                </Grid>

            </div>
        );
    }
}

export default TrackingUserList;
