  getBackground(index) {
    var value = index * 10;
    if (index <= 8) {
      const red = 150 + value;
      const blue = 132 + value;
      return `rgb(${red}, 0, ${blue})`;
    }
    value = index * 15;
    const blueValue = index * 3;
    const green = 0 + value;
    const blue = 212 + blueValue;
    return `rgb(255, ${green}, ${blue})`;
  }

  getColor(index) {
    if (index <= 3) {
      return "#fff";
    }
    return "#000";
  }

  filterItems(branch = "") {
    this.setState({
      selectedBranch: branch,
    });
    if (!branch) {
      this.setState(
        {
          billItems: this.state.selectedItems,
        },
        () => {
          this.groupByForThermalPrintOut();
        }
      );
    } else {
      const temp = [];
      this.state.selectedItems.forEach((p) => {
        const itemTemp = [];
        p.pastry.forEach((c) => {
          if (c.employees && c.employees[0] && c.employees[0]._id == branch) {
            itemTemp.push(c);
          }
        });
        if (itemTemp.length > 0) {
          p.pastry = itemTemp;
          temp.push(p);
        }
      });

      this.setState(
        {
          billItems: temp,
        },
        () => {
          this.groupByForThermalPrintOut();
        }
      );
    }
  }

  groupByForThermalPrintOut() {
    const temp = [];
    let amt = 0;
    let qty = 0;
    this.state.billItems.forEach((item) => {
      item.pastry.forEach((itemSub) => {
        itemSub.productCategory = item.productCategory;
        itemSub.item_id = item._id;
        itemSub.employee = itemSub.employees[0];
        temp.push(itemSub);
      });
    });
    const grouped = _.groupBy(temp, function (order) {
      return order.employee._id;
    });
    const printFormat = [];

    Object.keys(grouped).map((key) => {
      const groupedByCat = _.groupBy(grouped[key], function (item) {
        if (item.productCategory) {
          return item.productCategory._id;
        }
      });

      const pastries = [];
      Object.keys(groupedByCat).map((pkey) => {
        if (groupedByCat[pkey][0].productCategory) {
          const innerItems = {
            label: groupedByCat[pkey][0].productCategory.name,
            items: groupedByCat[pkey],
          };
          pastries.push(innerItems);
        }
      });

      const $item = {
        label: grouped[key][0].employee.firstname,
        pastries: pastries,
      };
      printFormat.push($item);
    });
 
    printFormat.forEach((item)=>{
      item.pastries.forEach((x)=>{
        x.items.forEach((y)=>{
          amt = amt + parseFloat(y.sendTotal);
          qty = qty + parseFloat(y.sendQty)
        })
      })
    })

    this.setState({
      printerFormatted: printFormat,
      allQty:(qty).toFixed(2),
      allAmount: (amt).toFixed(2)
    });
  }

  getTotalValue(type, items) {
    let val = 0;
    if (type === "price") {
      items.forEach((item) => {
        val = val + parseFloat(item.sendTotal);
      });
    } else if (type === "qty") {
      items.forEach((item) => {
        val = val + parseFloat(item.sendQty);
      });
    }

    return val.toFixed(2);
  }

