
import React, { Component } from "react";
import { Grid, Row, Col } from "react-bootstrap";
import NotificationSystem from "react-notification-system";
import axios from 'axios';
import { style } from "../../variables/Variables.jsx";
import '../../assets/css/custom.css';
import { authHeader } from '../../configs/helpers';
import { apiUrls } from '../../configs/configs';
import * as moment from 'moment';
import ReactToPrint from 'react-to-print';
import './billstyle.css';
import Modal from 'react-modal';

const customStyles = {
    content: {
        top: '50%',
        left: '50%',
        right: 'auto',
        bottom: 'auto',
        marginRight: '-50%',
        transform: 'translate(-50%, -50%)',
        height: '500px', // <-- This sets the height
        overlfow: 'scroll' // <-- This tells the modal to scrol
    },
};

class ViewDetailPastryOrder extends Component {
    constructor(props) {
        super(props);
        this.state = {
            details: null,
            orderId: this.props.match.params.id,
            qty: '',
            viewPopUp: false,
            allPastries: [],
            tempData: null,
            tempTotal: 0,
            tempPrice: 0
        }
    }

    componentDidMount() {
        this.getOrderDetails();
    }

    UNSAFE_componentWillReceiveProps(nextProps) {
        if (nextProps.match.params && nextProps.match.params.id) {
            this.setState({ orderId: nextProps.match.params.id }, () => {
                this.getOrderDetails();
            })
        }
    }

    getPastryName(id) {
        let name = 'N/A';
        if (this.state.allPastries.length > 0) {
            this.state.allPastries.forEach(item => {
                if (item._id === id) {
                    name = item.name
                }
            })
        }
        return name;
    }

    getPastryUnitName(id) {
        let name = '';
        if (this.state.allPastries.length > 0) {
            this.state.allPastries.forEach(item => {
                if (item._id === id) {
                    name = item.unitDetails ? item.unitDetails.name : ''
                }
            })
        }
        return name;
    }

    getOrderDetails() {
        axios({
            method: 'GET',
            url: apiUrls.ORDERS.getOnePastry + this.state.orderId,
            headers: {
                Authorization: authHeader()
            }
        }).then(result => {
            if (result.status === 200 && result.data.data) {
                const iData = result.data.data[0];
                const newPas = [];
                if (iData.pastry.length > 0) {
                    iData.pastry.forEach(item => {
                        item.tempQty = item.qty;
                        newPas.push(item);
                    })
                }

                this.setState({
                    details: iData,
                    tempData: newPas,
                    allPastries: result.data.data[0].pastryDetails,
                    tempTotal: iData.qty,
                    tempPrice: iData.total
                });


            } else {
                this.setState({
                    details: null
                });
            }
        }).catch(e => {
            this.setState({
                details: null
            });
        });
    }

    updateQuantity = () => {
        this.setState({ _notificationSystem: this.refs.notificationSystem, isFormSubmit: true });
        var _notificationSystem = this.refs.notificationSystem;
        const newPas = [];
        if (this.state.tempData.length > 0) {
            this.state.tempData.forEach(item => {
                item.sendQty = item.tempQty;
                item.sendTotal = item.tempQty * item.price;
                newPas.push(item);
            })
        }

        var bodyFormData = {
            pastry: newPas,
            sendTotal: this.state.tempPrice,
            sendQty: this.state.tempTotal
        };

        axios({
            method: 'POST',
            url: apiUrls.ORDERS.getOnePastry + this.state.orderId,
            data: bodyFormData,
            headers: {
                'Content-Type': 'application/json',
                Authorization: authHeader()
            }
        }).then(result => {
            if (result.status === 200) {
                this.getOrderDetails();
                _notificationSystem.addNotification({
                    title: <span data-notify="icon" className="pe-7s-check" />,
                    message: (
                        <div>
                            Status updated.
                        </div>
                    ),
                    level: 'success',
                    position: "tr",
                    autoDismiss: 15
                });
                this.setState({ viewPopUp: false })
            }
        }).catch(e => {
            _notificationSystem.addNotification({
                title: <span data-notify="icon" className="pe-7s-close-circle" />,
                message: (
                    <div>
                        {(e.response) ? e.response.data.message : 'Something went wrong!'}
                    </div>
                ),
                level: 'error',
                position: "tr",
                autoDismiss: 15
            });
        });
    }

    calculateTotal = (value, item) => {
        if (value) {
            let selected = 0;
            let totalPrice = 0;
            const matchId = item._id;
            const tempDetails = [];
            const pastryL = this.state.tempData;

            pastryL.forEach(item => {
                let tempQ = item;
                let quty = tempQ.tempQty;
                if (tempQ._id === matchId) {
                    // if (type === 'add') {
                    //     quty = parseInt(quty) + 1;
                    // } else if (quty > 1) {
                    //     quty = parseInt(quty) - 1;
                    // }
                    quty = parseInt(value);
                }
                tempQ.tempQty = quty;
                tempDetails.push(tempQ);
                selected = parseInt(selected) + parseInt(quty);
                totalPrice = totalPrice + (quty * item.price);
            });

            this.setState({
                tempData: tempDetails,
                tempTotal: selected,
                tempPrice: totalPrice
            });
        }
    }

    closeModal = () => {
        this.setState({
            viewPopUp: false
        })
    }


    render() {
        return (
            <div className="content">
                <NotificationSystem ref="notificationSystem" style={style} />
                <Grid fluid>
                    <Modal
                        isOpen={this.state.viewPopUp}
                        ariaHideApp={false}
                        style={customStyles}
                        contentLabel="Product Modal"
                    >
                        <h3>Change Products qty</h3>
                        <div className="products-wrap">
                            {this.state.tempData && (<table border="0" cellSpacing="0" cellPadding="0">
                                <thead>
                                    <tr>
                                        <th>#</th>
                                        <th className="text-left">Product</th>
                                        <th className="text-right">/ Price</th>
                                        <th className="text-right">Quantity Order</th>
                                        <th className="text-right">TOTAL</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {this.state.tempData.length > 0 && (
                                        this.state.tempData.map((item, key) => {
                                            return (<tr key={key + 1}>
                                                <td className="no">{key + 1}</td>
                                                <td className="text-left">{this.getPastryName(item._id)}</td>
                                                <td className="unit">₹{item.price}</td>
                                                <td className="qty">
                                                    <div className="qty-custom">
                                                        <input type="number" className="number-input-qty" defaultValue={item.tempQty} onKeyUp={(e) => this.calculateTotal(e.target.value, item)} />
                                                        {/* <button onClick={() => this.calculateTotal('add', item)}>+</button>
                                                        <p>{item.tempQty ? item.tempQty : item.qty}</p>
                                                        <button onClick={() => this.calculateTotal('sub', item)}>-</button> */}
                                                    </div>
                                                </td>

                                                <td className="total">₹ {(item.tempQty ? item.tempQty : item.qty) * item.price}</td>
                                            </tr>)
                                        })
                                    )}
                                </tbody>
                                <tfoot>
                                    <tr>
                                        <td colSpan="2"></td>
                                        <td colSpan="2">Total Items</td>
                                        <td>{(this.state.tempTotal) ? this.state.tempTotal : '-'}</td>
                                    </tr>
                                    <tr>
                                        <td colSpan="2"></td>
                                        <td colSpan="2">Total Price</td>
                                        <td>₹ {(this.state.tempPrice) ? this.state.tempPrice : '-'}</td>
                                    </tr>
                                    <tr>
                                        <td colSpan="2"></td>
                                        <td colSpan="2">GRAND TOTAL</td>
                                        <td>₹ {(this.state.tempPrice) ? this.state.tempPrice : '-'}</td>
                                    </tr>
                                </tfoot>
                            </table>)}

                            <div className="modal-foot">
                                <button onClick={() => this.closeModal()}>Close</button>
                                <button onClick={() => this.updateQuantity()}>Update</button>
                            </div>
                        </div>
                    </Modal>


                    <Row>
                        <Col>
                            {this.state.details && (<div className="order-view-bg">
                                <h2 className="text-capitalize">Branch orders</h2>
                                <p className="text-capitalize">Pastries</p>
                                <Row>

                                    <Col md={12}>
                                        <div className="toolbar hidden-print">
                                            <div className="text-right">
                                                <button id="printInvoice" className="btn btn-info mar-r-2" onClick={() => this.setState({ viewPopUp: true })}> Change Order Quantity</button>

                                                <ReactToPrint
                                                    trigger={() => {
                                                        // NOTE: could just as easily return <SomeComponent />. Do NOT pass an `onClick` prop
                                                        // to the root node of the returned component as it will be overwritten.
                                                        return <button id="printInvoice" className="btn btn-info"><i className="fa fa-print"></i> Print</button>
                                                    }}
                                                    content={() => this.componentRef}
                                                />
                                            </div>
                                            <hr />
                                        </div>
                                        <div className="invoice overflow-auto" ref={el => (this.componentRef = el)}>
                                            <div>
                                                <main>
                                                    <div className="row contacts">
                                                        <div className="col invoice-details">
                                                            <h1 className="invoice-id text-left">Order No {(this.state.details.form_no) ? this.state.details.form_no : '-'}</h1>
                                                            {this.state.details.productCategory && (<div className="date text-left mar-btm-5px">Category: <span className="pill-fill">{(this.state.details.productCategory) ? this.state.details.productCategory.name : '-'}</span></div>)}
                                                            <div className="date text-left">Ordered By: {(this.state.details.employees[0]) ? this.state.details.employees[0].firstname + this.state.details.employees[0].lastname : '-'}</div>
                                                            <div className="date text-left">Date of Order: {(this.state.details.created_at) ? moment(this.state.details.created_at).format('DD-MM-YYYY') + ' @ ' + moment(this.state.details.created_at).format('h:mm a') : '-'}</div>

                                                        </div>
                                                    </div>
                                                    <hr />
                                                    <table border="0" cellSpacing="0" cellPadding="0">
                                                        <thead>
                                                            <tr>
                                                                <th>#</th>
                                                                <th className="text-left">Products</th>
                                                                <th className="text-right">Quantity Order</th>
                                                                <th className="text-right">Unit Price</th>
                                                                <th className="text-right">Total Price</th>
                                                                <th className="text-right">Sending Qty</th>
                                                                <th className="text-right">Unit Price</th>
                                                                <th className="text-right">Sending Total</th>
                                                            </tr>
                                                        </thead>
                                                        <tbody>
                                                            {this.state.details.pastry.length > 0 && (
                                                                this.state.details.pastry.map((item, key) => {
                                                                    return (<tr key={Math.random()}>
                                                                        <td className="no">{key + 1}</td>
                                                                        <td className="text-left">{this.getPastryName(item._id)}</td>
                                                                        <td className="qty">{item.qty}</td>
                                                                        <td className="unit">₹{item.price} {this.getPastryUnitName(item._id) ? '/' + this.getPastryUnitName(item._id) : ''}</td>
                                                                        <td className="total">₹ {item.qty * item.price}</td>
                                                                        <td className="qty">{item.sendQty}</td>
                                                                        <td className="unit">₹{item.price}</td>
                                                                        <td className="total">₹ {item.sendQty * item.price}</td>

                                                                    </tr>)
                                                                })
                                                            )}


                                                        </tbody>
                                                        <tfoot>
                                                            <tr>
                                                                <td colSpan="2"></td>
                                                                <td colSpan="2">Total Ordered Items</td>
                                                                <td>{(this.state.details.qty) ? this.state.details.qty : '-'}</td>
                                                                {/* sending items */}
                                                                <td colSpan="1"></td>
                                                                <td colSpan="1">Total Sending Items</td>
                                                                <td>{(this.state.details.sendQty) ? this.state.details.sendQty : '-'}</td>

                                                            </tr>
                                                            <tr>
                                                                <td colSpan="2"></td>
                                                                <td colSpan="2">Total Ordered Items Price</td>
                                                                <td>₹ {(this.state.details.total) ? this.state.details.total : '-'}</td>
                                                                {/* sending items */}
                                                                <td colSpan="1"></td>
                                                                <td colSpan="1">Total Sending Items Price</td>
                                                                <td>₹ {(this.state.details.sendTotal) ? this.state.details.sendTotal : '-'}</td>

                                                            </tr>
                                                            <tr>
                                                                <td colSpan="2"></td>
                                                                <td colSpan="2">Grand Total</td>
                                                                <td>₹ {(this.state.details.total) ? this.state.details.total : '-'}</td>
                                                                {/* sending items */}
                                                                <td colSpan="1"></td>
                                                                <td colSpan="1">Grand Total</td>
                                                                <td>₹ {(this.state.details.sendTotal) ? this.state.details.sendTotal : '-'}</td>

                                                            </tr>

                                                        </tfoot>
                                                    </table>
                                                </main>
                                            </div>
                                        </div>
                                        {this.state.details.messages && (<div className="message-box">
                                            <h3>Message</h3>
                                            <p>{this.state.details.messages}</p>
                                        </div>)}

                                    </Col>
                                </Row>

                            </div>)}
                        </Col>


                    </Row>
                </Grid>
            </div>
        );
    }
}

export default ViewDetailPastryOrder;
