  getBackground(index) {
    var value = index * 10;
    if (index <= 8) {
      const red = 150 + value;
      const blue = 132 + value;
      return `rgb(${red}, 0, ${blue})`;
    }
    value = index * 15;
    const blueValue = index * 3;
    const green = 0 + value;
    const blue = 212 + blueValue;
    return `rgb(255, ${green}, ${blue})`;
  }

  getColor(index) {
    if (index <= 3) {
      return "#fff";
    }
    return "#000";
  }

  groupByForThermalPrintOut() {
    const temp = [];
    this.state.billItems.forEach((item) => {
      item.pastry.forEach((itemSub) => {
        itemSub.productCategory = item.productCategory;
        itemSub.item_id = item._id;
        itemSub.employee = itemSub.employees;
        temp.push(itemSub);
      });
    });
    const grouped = _.groupBy(temp, function (order) {
      if (order.employee) {
        return order.employee._id;
      }
    });
    const printFormat = [];

    Object.keys(grouped).map((key) => {
      const groupedByCat = _.groupBy(grouped[key], function (item) {
        if (item.productCategory) {
          return item.productCategory._id;
        }
      });

      const pastries = [];
      Object.keys(groupedByCat).map((pkey) => {
        if (groupedByCat[pkey][0].productCategory) {
          const innerItems = {
            label: groupedByCat[pkey][0].productCategory.name,
            items: groupedByCat[pkey],
          };
          pastries.push(innerItems);
        }
      });

      const $item = {
        label: grouped[key][0].employee.firstname,
        pastries: pastries,
      };
      printFormat.push($item);
    });

    this.setState({
      printerFormatted: printFormat,
    });
  }

  getTotalValue(type, items) {
    let val = 0;
    if (type === "price") {
      items.forEach((item) => {
        if (item.qty && item.qty[0]) {
          val = val + parseFloat(item.qty[0].items);
        }
      });
    } else if (type === "qty") {
      items.forEach((item) => {
        if (item.qty && item.qty[0]) {
          val =
            val +
            parseFloat(item.qty[0].items) *
              parseFloat(item.pastryDetails.price);
        }
      });
    }

    return val.toFixed(2);
  }

